import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const typedTexts = [
  'Laravel Developer',
  'Node.js Expert',
  'NestJS Architect',
  'Full Stack Developer',
  'API Specialist',
];

export default function Hero() {
  const [typedIndex, setTypedIndex]   = useState(0);
  const [displayed, setDisplayed]     = useState('');
  const [isDeleting, setIsDeleting]   = useState(false);

  // Typing animation
  useEffect(() => {
    const current = typedTexts[typedIndex];
    const speed   = isDeleting ? 60 : 100;

    const timer = setTimeout(() => {
      if (!isDeleting) {
        setDisplayed(current.substring(0, displayed.length + 1));
        if (displayed.length === current.length) {
          setTimeout(() => setIsDeleting(true), 1500);
        }
      } else {
        setDisplayed(current.substring(0, displayed.length - 1));
        if (displayed.length === 0) {
          setIsDeleting(false);
          setTypedIndex((typedIndex + 1) % typedTexts.length);
        }
      }
    }, speed);

    return () => clearTimeout(timer);
  }, [displayed, isDeleting, typedIndex]);

  return (
    <section className="hero">
      <div className="container">
        <div className="hero-inner">

          {/* Left Content */}
          <div data-aos="fade-right">
            <div className="hero-tag">
              Available for freelance work
            </div>

            <h1 className="hero-title">
              Hi, I Build<br />
              <span>Powerful Web</span><br />
              Applications
            </h1>

            <div className="hero-typed">
              I'm a <strong>{displayed}<span style={{
                borderRight: '2px solid var(--secondary)',
                marginLeft: 2,
                animation: 'blink 1s infinite',
              }}>|</span></strong>
            </div>

            <p className="hero-desc">
              With 12+ years of experience in PHP, Laravel, Node.js
              and modern web technologies. I build scalable,
              production-ready applications that drive business growth.
            </p>

            <div className="hero-btns">
              <Link to="/portfolio" className="btn btn-primary">
                View My Work 🚀
              </Link>
              <Link to="/contact" className="btn btn-outline">
                Hire Me Now
              </Link>
            </div>

            {/* Stats */}
            <div className="hero-stats">
              {[
                { num: '12+', label: 'Years Experience' },
                { num: '100+', label: 'Projects Done' },
                { num: '50+', label: 'Happy Clients' },
              ].map((stat, i) => (
                <div key={i}>
                  <div className="hero-stat-num">{stat.num}</div>
                  <div className="hero-stat-label">{stat.label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Right Image */}
          <div className="hero-image-wrap" data-aos="fade-left">
            <div className="hero-image-bg">

              {/* Profile Image */}
              <div style={{
                width: 340,
                height: 340,
                borderRadius: '50%',
                background: 'linear-gradient(135deg, #667eea, #764ba2)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 120,
                border: '6px solid white',
                boxShadow: 'var(--shadow-lg)',
              }}>
                👨‍💻
              </div>

              {/* Badge 1 */}
              <div className="hero-badge hero-badge-1">
                <div className="hero-badge-icon" style={{ background: 'rgba(37,99,235,0.1)' }}>
                  ⚡
                </div>
                <div>
                  <div style={{ fontSize: 15, fontWeight: 700 }}>12+ Years</div>
                  <div style={{ fontSize: 11, color: 'var(--gray)' }}>Experience</div>
                </div>
              </div>

              {/* Badge 2 */}
              <div className="hero-badge hero-badge-2">
                <div className="hero-badge-icon" style={{ background: 'rgba(34,197,94,0.1)' }}>
                  ✅
                </div>
                <div>
                  <div style={{ fontSize: 15, fontWeight: 700 }}>100+ Projects</div>
                  <div style={{ fontSize: 11, color: 'var(--gray)' }}>Completed</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes blink {
          0%, 100% { opacity: 1; }
          50% { opacity: 0; }
        }
        .mobile-menu-btn {
          display: none !important;
        }
        @media (max-width: 768px) {
          .mobile-menu-btn {
            display: block !important;
          }
        }
      `}</style>
    </section>
  );
}