import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AOS from 'aos';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import API from '../api/axios';

const defaultProjects = [
  { title: 'E-Commerce Platform', category: 'web', description: 'Full-featured WooCommerce store with custom payment gateway and inventory management.', tech_stack: 'Laravel,React,MySQL,Stripe', icon: '🛒' },
  { title: 'SaaS Dashboard', category: 'web', description: 'Multi-tenant SaaS app with role-based access control and real-time analytics.', tech_stack: 'NestJS,React,TypeORM,JWT', icon: '📊' },
  { title: 'REST API System', category: 'api', description: 'High-performance REST API serving 50K+ requests/day with caching.', tech_stack: 'Node.js,Express,Redis,MySQL', icon: '🔗' },
  { title: 'Job Portal', category: 'web', description: 'Complete job portal with employer/candidate dashboards and payment integration.', tech_stack: 'Laravel,Vue.js,MySQL,Stripe', icon: '💼' },
  { title: 'Hospital Management', category: 'web', description: 'Full hospital management system with appointments, billing and reports.', tech_stack: 'Laravel,jQuery,MySQL,AJAX', icon: '🏥' },
  { title: 'Mobile API Backend', category: 'api', description: 'RESTful backend for iOS/Android app with push notifications and real-time chat.', tech_stack: 'Node.js,Socket.io,MongoDB,FCM', icon: '📱' },
];

const categories = ['all', 'web', 'mobile', 'api'];

export default function Portfolio() {
  const [projects, setProjects]     = useState([]);
  const [filtered, setFiltered]     = useState([]);
  const [activeFilter, setFilter]   = useState('all');
  const [loading, setLoading]       = useState(true);
  const [page, setPage]             = useState(1);
  const [pagination, setPagination] = useState({});

  useEffect(() => {
    AOS.init({ duration: 800, once: true });
    fetchProjects();
  }, [page, activeFilter]);

  const fetchProjects = () => {
    setLoading(true);
    const category = activeFilter === 'all' ? '' : activeFilter;
    API.get(`/api/projects?page=${page}&perPage=6&category=${category}`)
      .then(({ data }) => {
        if (data.data?.length > 0) {
          setProjects(data.data);
          setFiltered(data.data);
          setPagination(data.pagination);
        } else {
          setProjects(defaultProjects);
          setFiltered(defaultProjects);
        }
        setLoading(false);
      })
      .catch(() => {
        setProjects(defaultProjects);
        setFiltered(defaultProjects);
        setLoading(false);
      });
  };

  const handleFilter = (cat) => {
    setFilter(cat);
    setPage(1);
    if (projects === defaultProjects) {
      setFiltered(cat === 'all'
        ? defaultProjects
        : defaultProjects.filter(p => p.category === cat)
      );
    }
  };

  return (
    <>
      <Navbar />

      <div className="page-hero">
        <div className="container">
          <h1>My <span style={{ color: 'var(--primary)' }}>Portfolio</span></h1>
          <p>A showcase of my best work across different technologies</p>
          <div className="breadcrumb">
            <Link to="/">Home</Link>
            <span>→</span>
            <span>Portfolio</span>
          </div>
        </div>
      </div>

      <section className="section">
        <div className="container">

          {/* Filter Buttons */}
          <div className="portfolio-filter" data-aos="fade-up">
            {categories.map(cat => (
              <button
                key={cat}
                className={`filter-btn ${activeFilter === cat ? 'active' : ''}`}
                onClick={() => handleFilter(cat)}
              >
                {cat.charAt(0).toUpperCase() + cat.slice(1)}
              </button>
            ))}
          </div>

          {/* Projects Grid */}
          {loading ? (
            <div className="loading">
              <div className="loading-spinner"></div>
              Loading projects...
            </div>
          ) : (
            <div className="portfolio-grid">
              {filtered.map((project, i) => (
                <div
                  className="project-card"
                  key={project.id || i}
                  data-aos="fade-up"
                  data-aos-delay={i * 80}
                >
                  <div className="project-image">
                    {project.image ? (
                      <img
                        src={`http://localhost:4000/${project.image}`}
                        alt={project.title}
                      />
                    ) : (
                      <div style={{
                        width: '100%',
                        height: '100%',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 70,
                        background: `hsl(${i * 45 + 200}, 70%, 95%)`,
                      }}>
                        {project.icon || '📁'}
                      </div>
                    )}
                    <div className="project-overlay">
                      {project.live_url && (
                        <a
                          href={project.live_url}
                          target="_blank"
                          rel="noreferrer"
                          className="project-link"
                        >
                          🔗
                        </a>
                      )}
                      {project.github_url && (
                        <a 
                          href={project.github_url}
                          target="_blank"
                          rel="noreferrer"
                          className="project-link"
                        >
                          📂
                        </a>
                      )}
                    </div>
                  </div>
                  <div className="project-body">
                    <div className="project-category">{project.category}</div>
                    <h3 className="project-title">{project.title}</h3>
                    <p className="project-desc">{project.description}</p>
                    {project.tech_stack && (
                      <div className="project-tags">
                        {project.tech_stack.split(',').map(tag => (
                          <span key={tag} className="project-tag">{tag.trim()}</span>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Pagination */}
          {pagination.totalPages > 1 && (
            <div className="pagination" style={{ marginTop: 40 }}>
              <button
                disabled={!pagination.hasPrev}
                onClick={() => setPage(p => p - 1)}
                style={{
                  padding: '10px 20px',
                  borderRadius: 8,
                  border: '2px solid var(--border)',
                  background: 'white',
                  cursor: 'pointer',
                  fontWeight: 600,
                }}
              >
                ← Prev
              </button>
              <span style={{ padding: '0 20px', color: 'var(--gray)' }}>
                {page} / {pagination.totalPages}
              </span>
              <button
                disabled={!pagination.hasNext}
                onClick={() => setPage(p => p + 1)}
                style={{
                  padding: '10px 20px',
                  borderRadius: 8,
                  border: '2px solid var(--border)',
                  background: 'white',
                  cursor: 'pointer',
                  fontWeight: 600,
                }}
              >
                Next →
              </button>
            </div>
          )}
        </div>
      </section>

      <Footer />
    </>
  );
}