import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import AdminLayout from '../../components/AdminLayout';
import API from '../../api/axios';

export default function AdminTestimonials() {
  const [items, setItems]         = useState([]);
  const [loading, setLoading]     = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing]     = useState(null);
  const [avatar, setAvatar]       = useState(null);
  const [form, setForm] = useState({
    client_name: '', client_title: '', client_country: '',
    message: '', rating: 5, is_featured: false,
  });

  useEffect(() => { fetchItems(); }, []);

  const fetchItems = () => {
    setLoading(true);
    API.get('/api/testimonials?perPage=50')
      .then(({ data }) => { setItems(data.data || []); setLoading(false); })
      .catch(() => setLoading(false));
  };

  const openCreate = () => {
    setEditing(null);
    setAvatar(null);
    setForm({ client_name: '', client_title: '', client_country: '', message: '', rating: 5, is_featured: false });
    setShowModal(true);
  };

  const openEdit = (item) => {
    setEditing(item);
    setAvatar(null);
    setForm({
      client_name:    item.client_name,
      client_title:   item.client_title   || '',
      client_country: item.client_country || '',
      message:        item.message,
      rating:         item.rating         || 5,
      is_featured:    item.is_featured    || false,
    });
    setShowModal(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      Object.keys(form).forEach(key => formData.append(key, form[key]));
      if (avatar) formData.append('client_avatar', avatar);

      if (editing) {
        await API.put(`/api/testimonials/${editing.id}`, formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Testimonial updated!');
      } else {
        await API.post('/api/testimonials', formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Testimonial created!');
      }
      setShowModal(false);
      fetchItems();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Something went wrong');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this testimonial?')) return;
    try {
      await API.delete(`/api/testimonials/${id}`);
      toast.success('Testimonial deleted!');
      fetchItems();
    } catch {
      toast.error('Failed to delete');
    }
  };

  return (
    <AdminLayout>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 700 }}>⭐ Testimonials</h1>
          <p style={{ color: 'var(--gray)', marginTop: 4 }}>Manage client reviews</p>
        </div>
        <button className="btn btn-primary" onClick={openCreate}>+ Add Testimonial</button>
      </div>

      <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid var(--border)', overflow: 'hidden' }}>
        {loading ? (
          <div className="loading"><div className="loading-spinner"></div></div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
            <thead>
              <tr>
                {['Client', 'Title', 'Rating', 'Featured', 'Message', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '14px 16px', textAlign: 'left', background: '#f8fafc', color: 'var(--gray)', fontSize: 12, fontWeight: 600, borderBottom: '1px solid var(--border)' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {items.length === 0 ? (
                <tr><td colSpan="6" style={{ textAlign: 'center', padding: 40, color: 'var(--gray)' }}>No testimonials yet</td></tr>
              ) : items.map(item => (
                <tr key={item.id} style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                      <div style={{ width: 36, height: 36, borderRadius: '50%', overflow: 'hidden', background: '#f0f7ff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18, flexShrink: 0 }}>
                        {item.client_avatar
                          ? <img src={`http://localhost:4000/${item.client_avatar}`} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                          : item.client_country || '👤'}
                      </div>
                      <span style={{ fontWeight: 500 }}>{item.client_name}</span>
                    </div>
                  </td>
                  <td style={{ padding: '12px 16px', color: 'var(--gray)', fontSize: 12 }}>{item.client_title || '—'}</td>
                  <td style={{ padding: '12px 16px', color: '#f59e0b' }}>{'★'.repeat(item.rating || 5)}</td>
                  <td style={{ padding: '12px 16px' }}>
                    <span style={{ padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600, background: item.is_featured ? 'rgba(34,197,94,0.1)' : 'rgba(100,116,139,0.1)', color: item.is_featured ? '#22c55e' : 'var(--gray)' }}>
                      {item.is_featured ? 'Featured' : 'Normal'}
                    </span>
                  </td>
                  <td style={{ padding: '12px 16px', color: 'var(--gray)', maxWidth: 200 }}>
                    <div style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {item.message}
                    </div>
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button className="btn btn-warning btn-sm" onClick={() => openEdit(item)}>Edit</button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleDelete(item.id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 20 }}
          onClick={() => setShowModal(false)}>
          <div style={{ background: 'white', borderRadius: 16, padding: 32, width: '100%', maxWidth: 520, maxHeight: '90vh', overflowY: 'auto' }}
            onClick={e => e.stopPropagation()}>
            <h3 style={{ marginBottom: 24, fontSize: 18, fontWeight: 600 }}>
              {editing ? '✏️ Edit Testimonial' : '➕ Add Testimonial'}
            </h3>
            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                <div className="form-group">
                  <label>Client Name *</label>
                  <input type="text" placeholder="John Smith" value={form.client_name}
                    onChange={e => setForm({ ...form, client_name: e.target.value })} required />
                </div>
                <div className="form-group">
                  <label>Title / Company</label>
                  <input type="text" placeholder="CEO, TechCorp" value={form.client_title}
                    onChange={e => setForm({ ...form, client_title: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>Country (emoji flag)</label>
                  <input type="text" placeholder="🇺🇸" value={form.client_country}
                    onChange={e => setForm({ ...form, client_country: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>Rating (1-5)</label>
                  <select value={form.rating}
                    onChange={e => setForm({ ...form, rating: +e.target.value })}>
                    {[5, 4, 3, 2, 1].map(r => (
                      <option key={r} value={r}>{'★'.repeat(r)} ({r})</option>
                    ))}
                  </select>
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Message *</label>
                  <textarea placeholder="What did the client say..." value={form.message}
                    onChange={e => setForm({ ...form, message: e.target.value })} required />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Client Avatar (Optional)</label>
                  <input type="file" accept="image/*"
                    onChange={e => setAvatar(e.target.files[0])} />
                  {editing?.client_avatar && !avatar && (
                    <img src={`http://localhost:4000/${editing.client_avatar}`} alt=""
                      style={{ marginTop: 8, height: 50, width: 50, borderRadius: '50%', objectFit: 'cover' }} />
                  )}
                </div>
                <div className="form-group" style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                  <input type="checkbox" id="feat" checked={form.is_featured}
                    onChange={e => setForm({ ...form, is_featured: e.target.checked })}
                    style={{ width: 18, height: 18 }} />
                  <label htmlFor="feat" style={{ margin: 0, cursor: 'pointer' }}>⭐ Featured</label>
                </div>
              </div>
              <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', marginTop: 8 }}>
                <button type="button" className="btn" style={{ background: '#f1f5f9' }}
                  onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" style={{ width: 'auto' }}>
                  {editing ? 'Update' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}