import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import AdminLayout from '../../components/AdminLayout';
import API from '../../api/axios';

export default function AdminSkills() {
  const [skills, setSkills]       = useState([]);
  const [loading, setLoading]     = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing]     = useState(null);
  const [form, setForm] = useState({
    name: '', percentage: 80, icon: '',
    category: 'backend', sort_order: 0,
  });

  useEffect(() => { fetchSkills(); }, []);

  const fetchSkills = () => {
    setLoading(true);
    API.get('/api/skills')
      .then(({ data }) => { setSkills(data.data || []); setLoading(false); })
      .catch(() => setLoading(false));
  };

  const openCreate = () => {
    setEditing(null);
    setForm({ name: '', percentage: 80, icon: '', category: 'backend', sort_order: 0 });
    setShowModal(true);
  };

  const openEdit = (skill) => {
    setEditing(skill);
    setForm({
      name:       skill.name,
      percentage: skill.percentage,
      icon:       skill.icon       || '',
      category:   skill.category   || 'backend',
      sort_order: skill.sort_order || 0,
    });
    setShowModal(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editing) {
        await API.put(`/api/skills/${editing.id}`, form);
        toast.success('Skill updated!');
      } else {
        await API.post('/api/skills', form);
        toast.success('Skill created!');
      }
      setShowModal(false);
      fetchSkills();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Something went wrong');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this skill?')) return;
    try {
      await API.delete(`/api/skills/${id}`);
      toast.success('Skill deleted!');
      fetchSkills();
    } catch {
      toast.error('Failed to delete');
    }
  };

  const categoryColors = {
    backend:  { bg: 'rgba(37,99,235,0.1)',   color: '#2563eb' },
    frontend: { bg: 'rgba(139,92,246,0.1)',  color: '#8b5cf6' },
    database: { bg: 'rgba(245,158,11,0.1)',  color: '#f59e0b' },
    tools:    { bg: 'rgba(16,185,129,0.1)',  color: '#10b981' },
  };

  return (
    <AdminLayout>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 700 }}>💡 Skills</h1>
          <p style={{ color: 'var(--gray)', marginTop: 4 }}>Manage your technical skills</p>
        </div>
        <button className="btn btn-primary" onClick={openCreate}>+ Add Skill</button>
      </div>

      <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid var(--border)', overflow: 'hidden' }}>
        {loading ? (
          <div className="loading"><div className="loading-spinner"></div></div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
            <thead>
              <tr>
                {['Skill', 'Category', 'Level', 'Progress', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '14px 16px', textAlign: 'left', background: '#f8fafc', color: 'var(--gray)', fontSize: 12, fontWeight: 600, borderBottom: '1px solid var(--border)' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {skills.length === 0 ? (
                <tr><td colSpan="5" style={{ textAlign: 'center', padding: 40, color: 'var(--gray)' }}>No skills yet</td></tr>
              ) : skills.map(skill => (
                <tr key={skill.id} style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '12px 16px', fontWeight: 500 }}>
                    {skill.icon && <span style={{ marginRight: 8 }}>{skill.icon}</span>}
                    {skill.name}
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <span style={{
                      padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600,
                      background: categoryColors[skill.category]?.bg || 'rgba(0,0,0,0.05)',
                      color: categoryColors[skill.category]?.color || 'var(--gray)',
                    }}>
                      {skill.category}
                    </span>
                  </td>
                  <td style={{ padding: '12px 16px', fontWeight: 600, color: 'var(--primary)' }}>
                    {skill.percentage}%
                  </td>
                  <td style={{ padding: '12px 16px', minWidth: 150 }}>
                    <div style={{ height: 8, background: '#f0f0f0', borderRadius: 4, overflow: 'hidden' }}>
                      <div style={{
                        height: '100%', width: `${skill.percentage}%`,
                        background: 'linear-gradient(90deg, var(--primary), var(--secondary))',
                        borderRadius: 4,
                      }} />
                    </div>
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button className="btn btn-warning btn-sm" onClick={() => openEdit(skill)}>Edit</button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleDelete(skill.id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 20 }}
          onClick={() => setShowModal(false)}>
          <div style={{ background: 'white', borderRadius: 16, padding: 32, width: '100%', maxWidth: 480 }}
            onClick={e => e.stopPropagation()}>
            <h3 style={{ marginBottom: 24, fontSize: 18, fontWeight: 600 }}>
              {editing ? '✏️ Edit Skill' : '➕ Add Skill'}
            </h3>
            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Skill Name *</label>
                  <input type="text" placeholder="Laravel / PHP" value={form.name}
                    onChange={e => setForm({ ...form, name: e.target.value })} required />
                </div>
                <div className="form-group">
                  <label>Category</label>
                  <select value={form.category}
                    onChange={e => setForm({ ...form, category: e.target.value })}>
                    <option value="backend">Backend</option>
                    <option value="frontend">Frontend</option>
                    <option value="database">Database</option>
                    <option value="tools">Tools</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>Icon (Emoji)</label>
                  <input type="text" placeholder="⚡" value={form.icon}
                    onChange={e => setForm({ ...form, icon: e.target.value })} />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Proficiency: {form.percentage}%</label>
                  <input
                    type="range" min="0" max="100"
                    value={form.percentage}
                    onChange={e => setForm({ ...form, percentage: +e.target.value })}
                    style={{ width: '100%', accentColor: 'var(--primary)' }}
                  />
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, color: 'var(--gray)', marginTop: 4 }}>
                    <span>Beginner</span>
                    <span>Intermediate</span>
                    <span>Expert</span>
                  </div>
                </div>
                <div className="form-group">
                  <label>Sort Order</label>
                  <input type="number" value={form.sort_order}
                    onChange={e => setForm({ ...form, sort_order: +e.target.value })} />
                </div>
              </div>
              <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', marginTop: 8 }}>
                <button type="button" className="btn" style={{ background: '#f1f5f9' }}
                  onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" style={{ width: 'auto' }}>
                  {editing ? 'Update' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}