import { NavLink, useNavigate } from 'react-router-dom';

const navItems = [
  { path: '/admin/dashboard',    icon: '📊', label: 'Dashboard' },
  { path: '/admin/projects',     icon: '📁', label: 'Projects' },
  { path: '/admin/services',     icon: '⚡', label: 'Services' },
  { path: '/admin/skills',       icon: '💡', label: 'Skills' },
  { path: '/admin/testimonials', icon: '⭐', label: 'Testimonials' },
  { path: '/admin/blog',         icon: '✍️', label: 'Blog' },
  { path: '/admin/contact',      icon: '📩', label: 'Messages' },
];

export default function AdminLayout({ children }) {
  const navigate = useNavigate();
  const admin    = JSON.parse(localStorage.getItem('admin') || '{}');

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('admin');
    navigate('/admin/login');
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#f8fafc' }}>

      {/* Sidebar */}
      <aside style={{
        width: 260,
        background: 'linear-gradient(180deg, #0f172a, #1e293b)',
        color: 'white',
        position: 'fixed',
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        zIndex: 100,
      }}>
        {/* Header */}
        <div style={{
          padding: '28px 24px',
          borderBottom: '1px solid rgba(255,255,255,0.08)',
        }}>
          <div style={{
            fontSize: 20,
            fontWeight: 800,
            fontFamily: 'Poppins, sans-serif',
            color: '#60a5fa',
            marginBottom: 4,
          }}>
            &lt;Codvex/&gt;
          </div>
          <div style={{ fontSize: 12, color: '#64748b' }}>Admin Panel</div>
        </div>

        {/* Admin Info */}
        <div style={{
          padding: '16px 24px',
          borderBottom: '1px solid rgba(255,255,255,0.06)',
          display: 'flex',
          alignItems: 'center',
          gap: 12,
        }}>
          <div style={{
            width: 38,
            height: 38,
            borderRadius: '50%',
            background: 'rgba(96,165,250,0.2)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: 18,
          }}>
            👤
          </div>
          <div>
            <div style={{ fontSize: 13, fontWeight: 600, color: 'white' }}>
              {admin.name || 'Admin'}
            </div>
            <div style={{ fontSize: 11, color: '#64748b' }}>Administrator</div>
          </div>
        </div>

        {/* Navigation */}
        <nav style={{ flex: 1, padding: '16px 0', overflowY: 'auto' }}>
          {navItems.map(item => (
            <NavLink
              key={item.path}
              to={item.path}
              style={({ isActive }) => ({
                display: 'flex',
                alignItems: 'center',
                gap: 12,
                padding: '11px 24px',
                fontSize: 14,
                fontWeight: 500,
                color: isActive ? 'white' : '#94a3b8',
                background: isActive ? 'rgba(96,165,250,0.15)' : 'transparent',
                borderLeft: isActive ? '3px solid #60a5fa' : '3px solid transparent',
                textDecoration: 'none',
                transition: 'all 0.2s',
              })}
            >
              <span>{item.icon}</span>
              {item.label}
            </NavLink>
          ))}
        </nav>

        {/* Footer */}
        <div style={{ padding: 16 }}>
          <button
            onClick={() => window.open('/', '_blank')}
            style={{
              width: '100%',
              padding: '10px',
              background: 'rgba(255,255,255,0.06)',
              color: '#94a3b8',
              border: 'none',
              borderRadius: 8,
              cursor: 'pointer',
              fontSize: 13,
              marginBottom: 8,
            }}
          >
            🌐 View Portfolio
          </button>
          <button
            onClick={logout}
            style={{
              width: '100%',
              padding: '10px',
              background: 'rgba(239,68,68,0.15)',
              color: '#f87171',
              border: 'none',
              borderRadius: 8,
              cursor: 'pointer',
              fontSize: 13,
            }}
          >
            🚪 Logout
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main style={{ marginLeft: 260, flex: 1, padding: 32 }}>
        {children}
      </main>
    </div>
  );
}