import { Link } from 'react-router-dom';

export default function Footer() {
  const year = new Date().getFullYear();

  return (
    <footer className="footer">
      <div className="container">
        <div className="footer-inner">

          {/* Brand */}
          <div className="footer-brand">
            <div className="navbar-logo" style={{ color: 'white' }}>
              &lt;Cod<span style={{ color: 'var(--primary)' }}>vex</span>/&gt;
            </div>
            <p>
              Building high-performance web applications with
              Laravel, Node.js, NestJS and React. 12+ years of
              delivering excellence.
            </p>
            <div className="social-links" style={{ marginTop: 20 }}>
              <a href="https://github.com" target="_blank" rel="noreferrer" className="social-link">🐙</a>
              <a href="https://linkedin.com" target="_blank" rel="noreferrer" className="social-link">💼</a>
              <a href="https://upwork.com" target="_blank" rel="noreferrer" className="social-link">🟢</a>
              <a href="https://twitter.com" target="_blank" rel="noreferrer" className="social-link">🐦</a>
            </div>
          </div>

          {/* Quick Links */}
          <div>
            <div className="footer-title">Quick Links</div>
            <div className="footer-links">
              <Link to="/">Home</Link>
              <Link to="/services">Services</Link>
              <Link to="/portfolio">Portfolio</Link>
              <Link to="/skills">Skills</Link>
            </div>
          </div>

          {/* More Links */}
          <div>
            <div className="footer-title">More</div>
            <div className="footer-links">
              <Link to="/blog">Blog</Link>
              <Link to="/testimonials">Testimonials</Link>
              <Link to="/contact">Contact</Link>
              <Link to="/admin/login">Admin</Link>
            </div>
          </div>

          {/* Services */}
          <div>
            <div className="footer-title">Services</div>
            <div className="footer-links">
              <a href="#services">Laravel Development</a>
              <a href="#services">Node.js APIs</a>
              <a href="#services">WordPress</a>
              <a href="#services">E-commerce</a>
            </div>
          </div>
        </div>

        {/* Bottom */}
        <div className="footer-bottom">
          <p>© {year} Codvex. All rights reserved.</p>
          <p>Built with ❤️ using NestJS + React</p>
        </div>
      </div>
    </footer>
  );
}