import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AOS from 'aos';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import API from '../api/axios';

const defaultBlogs = [
  { title: 'Building REST APIs with NestJS and TypeORM', slug: 'nestjs-typeorm-api', category: 'Node.js', excerpt: 'A complete guide to building production-ready REST APIs using NestJS framework with TypeORM and MySQL database.', created_at: new Date(), views: 245 },
  { title: 'Laravel Best Practices in 2026', slug: 'laravel-best-practices-2026', category: 'Laravel', excerpt: 'Essential best practices every Laravel developer should follow for clean, maintainable and scalable code.', created_at: new Date(), views: 312 },
  { title: 'How to Become a Top-Rated Freelancer on Upwork', slug: 'top-rated-upwork-freelancer', category: 'Career', excerpt: 'Proven strategies to build your Upwork profile, win clients and grow your freelance income consistently.', created_at: new Date(), views: 189 },
  { title: 'JWT Authentication with Node.js Explained', slug: 'jwt-auth-nodejs', category: 'Node.js', excerpt: 'Step by step guide to implementing secure JWT authentication in Node.js APIs with refresh tokens.', created_at: new Date(), views: 178 },
  { title: 'WooCommerce Custom Plugin Development', slug: 'woocommerce-plugin-development', category: 'WordPress', excerpt: 'Learn how to build custom WooCommerce plugins for payment gateways, shipping and product customization.', created_at: new Date(), views: 234 },
  { title: 'MySQL Query Optimization Tips', slug: 'mysql-optimization-tips', category: 'Database', excerpt: 'Practical tips for optimizing slow MySQL queries using indexes, explain plans and query restructuring.', created_at: new Date(), views: 156 },
];

const blogIcons = ['💻', '🔧', '💼', '🔐', '🛒', '🗄️'];

export default function Blog() {
  const [blogs, setBlogs]           = useState([]);
  const [categories, setCategories] = useState([]);
  const [activeCategory, setActive] = useState('');
  const [loading, setLoading]       = useState(true);
  const [page, setPage]             = useState(1);
  const [pagination, setPagination] = useState({});

  useEffect(() => {
    AOS.init({ duration: 800, once: true });
    fetchCategories();
  }, []);

  useEffect(() => {
    fetchBlogs();
  }, [page, activeCategory]);

  const fetchCategories = () => {
    API.get('/api/blog/categories')
      .then(({ data }) => setCategories(data.data || []))
      .catch(() => {});
  };

  const fetchBlogs = () => {
    setLoading(true);
    API.get(`/api/blog?page=${page}&perPage=6&category=${activeCategory}`)
      .then(({ data }) => {
        if (data.data?.length > 0) {
          setBlogs(data.data);
          setPagination(data.pagination);
        } else {
          setBlogs(defaultBlogs);
        }
        setLoading(false);
      })
      .catch(() => {
        setBlogs(defaultBlogs);
        setLoading(false);
      });
  };

  const handleCategory = (cat) => {
    setActive(cat);
    setPage(1);
  };

  return (
    <>
      <Navbar />

      <div className="page-hero">
        <div className="container">
          <h1>My <span style={{ color: 'var(--primary)' }}>Blog</span></h1>
          <p>Tips, tutorials and insights on web development</p>
          <div className="breadcrumb">
            <Link to="/">Home</Link>
            <span>→</span>
            <span>Blog</span>
          </div>
        </div>
      </div>

      <section className="section">
        <div className="container">

          {/* Category Filter */}
          {categories.length > 0 && (
            <div className="portfolio-filter" data-aos="fade-up">
              <button
                className={`filter-btn ${activeCategory === '' ? 'active' : ''}`}
                onClick={() => handleCategory('')}
              >
                All
              </button>
              {categories.map(cat => (
                <button
                  key={cat}
                  className={`filter-btn ${activeCategory === cat ? 'active' : ''}`}
                  onClick={() => handleCategory(cat)}
                >
                  {cat}
                </button>
              ))}
            </div>
          )}

          {/* Blog Grid */}
          {loading ? (
            <div className="loading">
              <div className="loading-spinner"></div>
              Loading articles...
            </div>
          ) : (
            <div className="blog-grid">
              {blogs.map((blog, i) => (
                <Link
                  to={`/blog/${blog.slug}`}
                  className="blog-card"
                  key={blog.id || i}
                  data-aos="fade-up"
                  data-aos-delay={i * 80}
                  style={{ textDecoration: 'none', display: 'block' }}
                >
                  <div className="blog-image">
                    {blog.image ? (
                      <img
                        src={`http://localhost:4000/${blog.image}`}
                        alt={blog.title}
                      />
                    ) : (
                      <div style={{
                        width: '100%',
                        height: '100%',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 60,
                        background: `hsl(${i * 45 + 200}, 70%, 95%)`,
                      }}>
                        {blogIcons[i % blogIcons.length]}
                      </div>
                    )}
                  </div>
                  <div className="blog-body">
                    <div className="blog-meta">
                      <span className="blog-category">{blog.category}</span>
                      <span className="blog-date">
                        {new Date(blog.created_at).toLocaleDateString('en-US', {
                          month: 'short', day: 'numeric', year: 'numeric'
                        })}
                      </span>
                    </div>
                    <h3 className="blog-title">{blog.title}</h3>
                    <p className="blog-excerpt">{blog.excerpt}</p>
                    <div className="blog-footer">
                      <span className="blog-read-more">Read More →</span>
                      <span className="blog-views">👁 {blog.views || 0}</span>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          )}

          {/* Pagination */}
          {pagination.totalPages > 1 && (
            <div style={{
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              gap: 8,
              marginTop: 40,
            }}>
              <button
                disabled={!pagination.hasPrev}
                onClick={() => setPage(p => p - 1)}
                style={{
                  padding: '10px 20px',
                  borderRadius: 8,
                  border: '2px solid var(--border)',
                  background: 'white',
                  cursor: 'pointer',
                  fontWeight: 600,
                  opacity: !pagination.hasPrev ? 0.4 : 1,
                }}
              >
                ← Prev
              </button>
              {[...Array(pagination.totalPages)].map((_, i) => (
                <button
                  key={i}
                  onClick={() => setPage(i + 1)}
                  style={{
                    padding: '10px 16px',
                    borderRadius: 8,
                    border: '2px solid',
                    borderColor: page === i + 1 ? 'var(--primary)' : 'var(--border)',
                    background: page === i + 1 ? 'var(--primary)' : 'white',
                    color: page === i + 1 ? 'white' : 'var(--dark)',
                    cursor: 'pointer',
                    fontWeight: 600,
                  }}
                >
                  {i + 1}
                </button>
              ))}
              <button
                disabled={!pagination.hasNext}
                onClick={() => setPage(p => p + 1)}
                style={{
                  padding: '10px 20px',
                  borderRadius: 8,
                  border: '2px solid var(--border)',
                  background: 'white',
                  cursor: 'pointer',
                  fontWeight: 600,
                  opacity: !pagination.hasNext ? 0.4 : 1,
                }}
              >
                Next →
              </button>
            </div>
          )}
        </div>
      </section>

      <Footer />
    </>
  );
}