import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import API from '../api/axios';

const defaultServices = [
  { icon: '⚡', title: 'Laravel Development', description: 'Building scalable, high-performance web applications with Laravel framework. From simple CRUD apps to complex enterprise systems with clean architecture, repositories, services and API resources.', price_from: 'From $500' },
  { icon: '🚀', title: 'Node.js & NestJS APIs', description: 'Production-ready REST APIs with Node.js and NestJS. JWT authentication, file uploads, pagination, real-time features and clean modular architecture.', price_from: 'From $400' },
  { icon: '🛒', title: 'E-Commerce Development', description: 'Custom WooCommerce, Shopify, OpenCart and BigCommerce solutions. Payment gateway integration, shipping APIs, inventory management and order processing.', price_from: 'From $600' },
  { icon: '🔧', title: 'Bug Fixing & Optimization', description: 'I specialize in fixing complex bugs that other developers cannot solve. Performance optimization, database query tuning and taking over difficult legacy projects.', price_from: 'From $50/hr' },
  { icon: '🌐', title: 'WordPress Development', description: 'Custom WordPress themes, plugins and WooCommerce stores. ACF integration, custom post types, REST API and performance optimization.', price_from: 'From $300' },
  { icon: '🔗', title: 'API Integration', description: 'Third-party API integrations including Stripe, PayPal, Twilio, SendGrid, shipping carriers, CRMs, social platforms and custom webhook systems.', price_from: 'From $200' },
  { icon: '🏗️', title: 'Legacy System Upgrade', description: 'Migrating and upgrading old Zend, Yii, CodeIgniter applications to modern Laravel or Node.js stack without breaking existing functionality.', price_from: 'From $800' },
  { icon: '☁️', title: 'VPS & Deployment', description: 'Server setup, deployment pipelines, Nginx configuration, SSL certificates, PM2 process management and database optimization on Linux VPS.', price_from: 'From $150' },
];

export default function Services() {
  const [services, setServices] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    AOS.init({ duration: 800, once: true });
    API.get('/api/services')
      .then(({ data }) => {
        setServices(data.data?.length > 0 ? data.data : defaultServices);
        setLoading(false);
      })
      .catch(() => {
        setServices(defaultServices);
        setLoading(false);
      });
  }, []);

  return (
    <>
      <Navbar />

      {/* Page Hero */}
      <div className="page-hero">
        <div className="container">
          <h1>My <span style={{ color: 'var(--primary)' }}>Services</span></h1>
          <p>Professional web development services tailored to your business needs</p>
          <div className="breadcrumb">
            <Link to="/">Home</Link>
            <span>→</span>
            <span>Services</span>
          </div>
        </div>
      </div>

      {/* Services Grid */}
      <section className="section">
        <div className="container">
          {loading ? (
            <div className="loading">
              <div className="loading-spinner"></div>
              Loading services...
            </div>
          ) : (
            <div className="services-grid">
              {services.map((service, i) => (
                <div
                  className="service-card"
                  key={service.id || i}
                  data-aos="fade-up"
                  data-aos-delay={i * 80}
                >
                  <div className="service-icon">{service.icon || '⚡'}</div>
                  <h3 className="service-title">{service.title}</h3>
                  <p className="service-desc">{service.description}</p>
                  {service.price_from && (
                    <div className="service-price">{service.price_from}</div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Process Section */}
      <section className="section" style={{ background: 'var(--light)' }}>
        <div className="container">
          <div className="section-header" data-aos="fade-up">
            <span className="section-tag">How I Work</span>
            <h2 className="section-title">My <span>Process</span></h2>
            <p className="section-subtitle">
              A clear, transparent process to ensure your project succeeds
            </p>
          </div>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
            gap: 24,
          }}>
            {[
              { step: '01', icon: '💬', title: 'Discovery', desc: 'We discuss your requirements, goals and timeline in detail.' },
              { step: '02', icon: '📋', title: 'Planning', desc: 'I create a detailed plan, architecture and accurate estimation.' },
              { step: '03', icon: '💻', title: 'Development', desc: 'Clean, tested code with regular updates and progress reports.' },
              { step: '04', icon: '🚀', title: 'Delivery', desc: 'Thorough testing, deployment and post-launch support.' },
            ].map((step, i) => (
              <div
                key={i}
                className="card"
                data-aos="fade-up"
                data-aos-delay={i * 100}
                style={{ textAlign: 'center' }}
              >
                <div style={{
                  fontSize: 13,
                  fontWeight: 700,
                  color: 'var(--primary)',
                  marginBottom: 12,
                  letterSpacing: '0.1em',
                }}>
                  STEP {step.step}
                </div>
                <div style={{ fontSize: 40, marginBottom: 16 }}>{step.icon}</div>
                <h3 style={{ fontSize: 18, marginBottom: 10 }}>{step.title}</h3>
                <p style={{ fontSize: 14, color: 'var(--gray)', lineHeight: 1.7 }}>
                  {step.desc}
                </p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section style={{
        background: 'linear-gradient(135deg, var(--primary), var(--secondary))',
        padding: '80px 0',
        textAlign: 'center',
        color: 'white',
      }}>
        <div className="container" data-aos="fade-up">
          <h2 style={{ fontSize: 36, marginBottom: 16 }}>
            Let's Work Together!
          </h2>
          <p style={{ opacity: 0.9, marginBottom: 32, fontSize: 16 }}>
            Ready to start your project? Get in touch and let's discuss your needs.
          </p>
          <Link to="/contact" className="btn btn-white">
            Get Free Quote 📩
          </Link>
        </div>
      </section>

      <Footer />
    </>
  );
}