import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import AOS from 'aos';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import API from '../api/axios';

export default function Contact() {
  const [form, setForm]     = useState({
    name: '', email: '', phone: '', subject: '', message: ''
  });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    AOS.init({ duration: 800, once: true });
    window.scrollTo(0, 0);
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await API.post('/api/contact', form);
      toast.success('Message sent successfully! I will reply within 24 hours. 🎉');
      setForm({ name: '', email: '', phone: '', subject: '', message: '' });
    } catch (err) {
      const msg = err.response?.data?.message;
      toast.error(Array.isArray(msg) ? msg[0] : msg || 'Failed to send message');
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <Navbar />

      <div className="page-hero">
        <div className="container">
          <h1>Get In <span style={{ color: 'var(--primary)' }}>Touch</span></h1>
          <p>Have a project in mind? Let's discuss it!</p>
          <div className="breadcrumb">
            <Link to="/">Home</Link>
            <span>→</span>
            <span>Contact</span>
          </div>
        </div>
      </div>

      <section className="section contact-section">
        <div className="container">
          <div className="contact-grid">

            {/* Contact Info */}
            <div data-aos="fade-right">
              <h3>Let's Work Together</h3>
              <p>
                I'm available for freelance projects, full-time positions
                and consulting. Feel free to reach out — I typically
                respond within 24 hours.
              </p>

              <div className="contact-items">
                {[
                  { icon: '📧', label: 'Email', value: 'hello@codvex.com' },
                  { icon: '💬', label: 'WhatsApp', value: '+92 300 0000000' },
                  { icon: '🟢', label: 'Upwork', value: 'upwork.com/fl/yourprofile' },
                  { icon: '📍', label: 'Location', value: 'Pakistan (Available Worldwide)' },
                  { icon: '⏰', label: 'Response Time', value: 'Within 24 hours' },
                ].map((item, i) => (
                  <div className="contact-item" key={i}>
                    <div className="contact-item-icon">{item.icon}</div>
                    <div>
                      <div className="contact-item-label">{item.label}</div>
                      <div className="contact-item-value">{item.value}</div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Availability Badge */}
              <div style={{
                marginTop: 32,
                padding: '16px 20px',
                background: 'rgba(34,197,94,0.08)',
                border: '2px solid rgba(34,197,94,0.2)',
                borderRadius: 'var(--radius)',
                display: 'flex',
                alignItems: 'center',
                gap: 12,
              }}>
                <div style={{
                  width: 12,
                  height: 12,
                  background: 'var(--success)',
                  borderRadius: '50%',
                  animation: 'pulse 2s infinite',
                }}></div>
                <div>
                  <div style={{ fontWeight: 600, color: 'var(--dark)', fontSize: 14 }}>
                    Available for new projects
                  </div>
                  <div style={{ fontSize: 12, color: 'var(--gray)', marginTop: 2 }}>
                    Currently accepting freelance work
                  </div>
                </div>
              </div>
            </div>

            {/* Contact Form */}
            <div data-aos="fade-left">
              <form className="contact-form" onSubmit={handleSubmit}>
                <h3 style={{ marginBottom: 24, fontSize: 20 }}>
                  Send Me a Message 📩
                </h3>

                <div className="form-row">
                  <div className="form-group">
                    <label>Your Name *</label>
                    <input
                      type="text"
                      name="name"
                      placeholder="John Smith"
                      value={form.name}
                      onChange={handleChange}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Email Address *</label>
                    <input
                      type="email"
                      name="email"
                      placeholder="john@example.com"
                      value={form.email}
                      onChange={handleChange}
                      required
                    />
                  </div>
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>Phone (Optional)</label>
                    <input
                      type="text"
                      name="phone"
                      placeholder="+1 234 567 8900"
                      value={form.phone}
                      onChange={handleChange}
                    />
                  </div>
                  <div className="form-group">
                    <label>Subject</label>
                    <input
                      type="text"
                      name="subject"
                      placeholder="Project Discussion"
                      value={form.subject}
                      onChange={handleChange}
                    />
                  </div>
                </div>

                <div className="form-group">
                  <label>Your Message *</label>
                  <textarea
                    name="message"
                    placeholder="Tell me about your project, requirements and timeline..."
                    value={form.message}
                    onChange={handleChange}
                    required
                    style={{ minHeight: 140 }}
                  />
                </div>

                <button
                  type="submit"
                  className="btn btn-primary"
                  style={{ width: '100%', justifyContent: 'center' }}
                  disabled={loading}
                >
                  {loading ? '⏳ Sending...' : '🚀 Send Message'}
                </button>

                <p style={{
                  fontSize: 12,
                  color: 'var(--gray)',
                  textAlign: 'center',
                  marginTop: 12,
                }}>
                  I typically respond within 24 hours ⚡
                </p>
              </form>
            </div>
          </div>
        </div>
      </section>

      <Footer />
    </>
  );
}