import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import AdminLayout from '../../components/AdminLayout';
import API from '../../api/axios';

export default function AdminContact() {
  const [messages, setMessages]   = useState([]);
  const [loading, setLoading]     = useState(true);
  const [page, setPage]           = useState(1);
  const [pagination, setPagination] = useState({});
  const [statusFilter, setStatus] = useState('');
  const [selected, setSelected]   = useState(null);

  useEffect(() => { fetchMessages(); }, [page, statusFilter]);

  const fetchMessages = () => {
    setLoading(true);
    API.get(`/api/contact?page=${page}&perPage=10&status=${statusFilter}`)
      .then(({ data }) => {
        setMessages(data.data || []);
        setPagination(data.pagination || {});
        setLoading(false);
      })
      .catch(() => setLoading(false));
  };

  const markAsRead = async (id) => {
    try {
      await API.patch(`/api/contact/${id}/read`);
      toast.success('Marked as read!');
      fetchMessages();
    } catch {
      toast.error('Failed to update');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this message?')) return;
    try {
      await API.delete(`/api/contact/${id}`);
      toast.success('Message deleted!');
      if (selected?.id === id) setSelected(null);
      fetchMessages();
    } catch {
      toast.error('Failed to delete');
    }
  };

  return (
    <AdminLayout>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 700 }}>📩 Messages</h1>
          <p style={{ color: 'var(--gray)', marginTop: 4 }}>
            Contact form submissions — {pagination.total || 0} total
          </p>
        </div>
        <select
          value={statusFilter}
          onChange={e => { setStatus(e.target.value); setPage(1); }}
          style={{ padding: '10px 16px', borderRadius: 8, border: '2px solid var(--border)', fontSize: 14, outline: 'none' }}
        >
          <option value="">All Messages</option>
          <option value="unread">Unread</option>
          <option value="read">Read</option>
          <option value="replied">Replied</option>
        </select>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: selected ? '1fr 1fr' : '1fr', gap: 20 }}>

        {/* Messages Table */}
        <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid var(--border)', overflow: 'hidden' }}>
          {loading ? (
            <div className="loading"><div className="loading-spinner"></div></div>
          ) : (
            <>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
                <thead>
                  <tr>
                    {['Name', 'Email', 'Subject', 'Status', 'Date', 'Actions'].map(h => (
                      <th key={h} style={{ padding: '14px 16px', textAlign: 'left', background: '#f8fafc', color: 'var(--gray)', fontSize: 12, fontWeight: 600, borderBottom: '1px solid var(--border)' }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {messages.length === 0 ? (
                    <tr><td colSpan="6" style={{ textAlign: 'center', padding: 40, color: 'var(--gray)' }}>No messages yet</td></tr>
                  ) : messages.map(msg => (
                    <tr
                      key={msg.id}
                      style={{
                        borderBottom: '1px solid #f0f0f0',
                        background: selected?.id === msg.id ? 'rgba(37,99,235,0.04)' : 'white',
                        cursor: 'pointer',
                      }}
                      onClick={() => setSelected(msg)}
                    >
                      <td style={{ padding: '12px 16px', fontWeight: msg.status === 'unread' ? 700 : 400 }}>
                        {msg.status === 'unread' && (
                          <span style={{ width: 8, height: 8, borderRadius: '50%', background: 'var(--primary)', display: 'inline-block', marginRight: 8 }} />
                        )}
                        {msg.name}
                      </td>
                      <td style={{ padding: '12px 16px', color: 'var(--gray)', fontSize: 12 }}>{msg.email}</td>
                      <td style={{ padding: '12px 16px', maxWidth: 150, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                        {msg.subject || '—'}
                      </td>
                      <td style={{ padding: '12px 16px' }}>
                        <span style={{
                          padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600,
                          background: msg.status === 'unread' ? 'rgba(239,68,68,0.1)' : msg.status === 'replied' ? 'rgba(34,197,94,0.1)' : 'rgba(100,116,139,0.1)',
                          color: msg.status === 'unread' ? '#ef4444' : msg.status === 'replied' ? '#22c55e' : 'var(--gray)',
                        }}>
                          {msg.status}
                        </span>
                      </td>
                      <td style={{ padding: '12px 16px', color: 'var(--gray)', fontSize: 12 }}>
                        {new Date(msg.created_at).toLocaleDateString()}
                      </td>
                      <td style={{ padding: '12px 16px' }} onClick={e => e.stopPropagation()}>
                        <div style={{ display: 'flex', gap: 6 }}>
                          {msg.status === 'unread' && (
                            <button
                              className="btn btn-sm"
                              style={{ background: 'rgba(37,99,235,0.1)', color: 'var(--primary)', padding: '4px 10px', fontSize: 11 }}
                              onClick={() => markAsRead(msg.id)}
                            >
                              ✓ Read
                            </button>
                          )}
                          <button className="btn btn-danger btn-sm" onClick={() => handleDelete(msg.id)}>
                            Delete
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>

              {/* Pagination */}
              {pagination.totalPages > 1 && (
                <div style={{ display: 'flex', justifyContent: 'center', gap: 8, padding: 16 }}>
                  <button disabled={!pagination.hasPrev} onClick={() => setPage(p => p - 1)}
                    style={{ padding: '8px 16px', borderRadius: 8, border: '2px solid var(--border)', background: 'white', cursor: 'pointer', opacity: !pagination.hasPrev ? 0.4 : 1 }}>
                    ← Prev
                  </button>
                  <span style={{ padding: '8px 16px', color: 'var(--gray)' }}>
                    {page} / {pagination.totalPages}
                  </span>
                  <button disabled={!pagination.hasNext} onClick={() => setPage(p => p + 1)}
                    style={{ padding: '8px 16px', borderRadius: 8, border: '2px solid var(--border)', background: 'white', cursor: 'pointer', opacity: !pagination.hasNext ? 0.4 : 1 }}>
                    Next →
                  </button>
                </div>
              )}
            </>
          )}
        </div>

        {/* Message Detail */}
        {selected && (
          <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid var(--border)', padding: 24 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
              <h3 style={{ fontSize: 16, fontWeight: 600 }}>📨 Message Detail</h3>
              <button onClick={() => setSelected(null)}
                style={{ background: 'none', border: 'none', fontSize: 20, cursor: 'pointer', color: 'var(--gray)' }}>
                ✕
              </button>
            </div>

            {/* Client Info */}
            <div style={{ background: '#f8fafc', borderRadius: 12, padding: 16, marginBottom: 20 }}>
              {[
                { label: '👤 Name',    value: selected.name },
                { label: '📧 Email',   value: selected.email },
                { label: '📱 Phone',   value: selected.phone   || '—' },
                { label: '📋 Subject', value: selected.subject || '—' },
                { label: '📅 Date',    value: new Date(selected.created_at).toLocaleString() },
              ].map((item, i) => (
                <div key={i} style={{ display: 'flex', gap: 12, marginBottom: 10, fontSize: 14 }}>
                  <span style={{ color: 'var(--gray)', minWidth: 100 }}>{item.label}:</span>
                  <span style={{ fontWeight: 500, color: 'var(--dark)' }}>{item.value}</span>
                </div>
              ))}
            </div>

            {/* Message */}
            <div style={{ background: '#f0f7ff', borderRadius: 12, padding: 16, marginBottom: 20 }}>
              <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--primary)', marginBottom: 8 }}>
                MESSAGE:
              </div>
              <p style={{ fontSize: 14, lineHeight: 1.8, color: 'var(--dark)' }}>
                {selected.message}
              </p>
            </div>

            {/* Actions */}
            <div style={{ display: 'flex', gap: 10 }}>
              <a
                href={`mailto:${selected.email}?subject=Re: ${selected.subject || 'Your message'}`}
                className="btn btn-primary"
                style={{ flex: 1, justifyContent: 'center' }}
              >
                📧 Reply via Email
              </a>
              <button
                className="btn btn-danger"
                onClick={() => handleDelete(selected.id)}
                style={{ width: 'auto' }}
              >
                Delete
              </button>
            </div>
          </div>
        )}
      </div>
    </AdminLayout>
  );
}