import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import AdminLayout from '../../components/AdminLayout';
import API from '../../api/axios';

export default function AdminProjects() {
  const [projects, setProjects]   = useState([]);
  const [loading, setLoading]     = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing]     = useState(null);
  const [image, setImage]         = useState(null);
  const [form, setForm] = useState({
    title: '', description: '', live_url: '',
    github_url: '', tech_stack: '', category: 'web',
    is_featured: false, sort_order: 0,
  });

  useEffect(() => { fetchProjects(); }, []);

  const fetchProjects = () => {
    setLoading(true);
    API.get('/api/projects?perPage=50')
      .then(({ data }) => { setProjects(data.data || []); setLoading(false); })
      .catch(() => setLoading(false));
  };

  const openCreate = () => {
    setEditing(null);
    setImage(null);
    setForm({
      title: '', description: '', live_url: '',
      github_url: '', tech_stack: '', category: 'web',
      is_featured: false, sort_order: 0,
    });
    setShowModal(true);
  };

  const openEdit = (project) => {
    setEditing(project);
    setImage(null);
    setForm({
      title:       project.title,
      description: project.description,
      live_url:    project.live_url    || '',
      github_url:  project.github_url  || '',
      tech_stack:  project.tech_stack  || '',
      category:    project.category    || 'web',
      is_featured: project.is_featured || false,
      sort_order:  project.sort_order  || 0,
    });
    setShowModal(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      Object.keys(form).forEach(key => formData.append(key, form[key]));
      if (image) formData.append('image', image);

      if (editing) {
        await API.put(`/api/projects/${editing.id}`, formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Project updated!');
      } else {
        await API.post('/api/projects', formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Project created!');
      }
      setShowModal(false);
      fetchProjects();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Something went wrong');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this project?')) return;
    try {
      await API.delete(`/api/projects/${id}`);
      toast.success('Project deleted!');
      fetchProjects();
    } catch {
      toast.error('Failed to delete project');
    }
  };

  return (
    <AdminLayout>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 700 }}>📁 Projects</h1>
          <p style={{ color: 'var(--gray)', marginTop: 4 }}>Manage your portfolio projects</p>
        </div>
        <button className="btn btn-primary" onClick={openCreate}>
          + Add Project
        </button>
      </div>

      {/* Table */}
      <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid var(--border)', overflow: 'hidden' }}>
        {loading ? (
          <div className="loading"><div className="loading-spinner"></div>Loading...</div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
            <thead>
              <tr>
                {['Image', 'Title', 'Category', 'Tech Stack', 'Featured', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '14px 16px', textAlign: 'left', background: '#f8fafc', color: 'var(--gray)', fontSize: 12, fontWeight: 600, borderBottom: '1px solid var(--border)' }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {projects.length === 0 ? (
                <tr><td colSpan="6" style={{ textAlign: 'center', padding: 40, color: 'var(--gray)' }}>No projects yet. Add your first project!</td></tr>
              ) : projects.map((project, i) => (
                <tr key={project.id} style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ width: 60, height: 45, borderRadius: 8, overflow: 'hidden', background: '#f0f7ff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24 }}>
                      {project.image
                        ? <img src={`http://localhost:4000/${project.image}`} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                        : '📁'}
                    </div>
                  </td>
                  <td style={{ padding: '12px 16px', fontWeight: 500 }}>{project.title}</td>
                  <td style={{ padding: '12px 16px' }}>
                    <span style={{ padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600, background: 'rgba(37,99,235,0.1)', color: 'var(--primary)' }}>
                      {project.category}
                    </span>
                  </td>
                  <td style={{ padding: '12px 16px', color: 'var(--gray)', fontSize: 12 }}>
                    {project.tech_stack?.split(',').slice(0, 3).join(', ') || '—'}
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <span style={{ padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600, background: project.is_featured ? 'rgba(34,197,94,0.1)' : 'rgba(100,116,139,0.1)', color: project.is_featured ? '#22c55e' : 'var(--gray)' }}>
                      {project.is_featured ? '⭐ Featured' : 'Normal'}
                    </span>
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button className="btn btn-warning btn-sm" onClick={() => openEdit(project)}>Edit</button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleDelete(project.id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 20 }}
          onClick={() => setShowModal(false)}>
          <div style={{ background: 'white', borderRadius: 16, padding: 32, width: '100%', maxWidth: 600, maxHeight: '90vh', overflowY: 'auto' }}
            onClick={e => e.stopPropagation()}>
            <h3 style={{ fontSize: 18, fontWeight: 600, marginBottom: 24 }}>
              {editing ? '✏️ Edit Project' : '➕ Add Project'}
            </h3>
            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Title *</label>
                  <input type="text" placeholder="E-commerce Platform" value={form.title}
                    onChange={e => setForm({ ...form, title: e.target.value })} required />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Description *</label>
                  <textarea placeholder="Describe your project..." value={form.description}
                    onChange={e => setForm({ ...form, description: e.target.value })} required />
                </div>
                <div className="form-group">
                  <label>Live URL</label>
                  <input type="url" placeholder="https://example.com" value={form.live_url}
                    onChange={e => setForm({ ...form, live_url: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>GitHub URL</label>
                  <input type="url" placeholder="https://github.com/..." value={form.github_url}
                    onChange={e => setForm({ ...form, github_url: e.target.value })} />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Tech Stack (comma separated)</label>
                  <input type="text" placeholder="Laravel,React,MySQL,Stripe" value={form.tech_stack}
                    onChange={e => setForm({ ...form, tech_stack: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>Category</label>
                  <select value={form.category} onChange={e => setForm({ ...form, category: e.target.value })}>
                    <option value="web">Web</option>
                    <option value="mobile">Mobile</option>
                    <option value="api">API</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>Sort Order</label>
                  <input type="number" value={form.sort_order}
                    onChange={e => setForm({ ...form, sort_order: +e.target.value })} />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Project Image</label>
                  <input type="file" accept="image/*"
                    onChange={e => setImage(e.target.files[0])} />
                  {editing?.image && !image && (
                    <img src={`http://localhost:4000/${editing.image}`} alt="" style={{ marginTop: 8, height: 60, borderRadius: 8 }} />
                  )}
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1', display: 'flex', alignItems: 'center', gap: 10 }}>
                  <input type="checkbox" id="featured" checked={form.is_featured}
                    onChange={e => setForm({ ...form, is_featured: e.target.checked })}
                    style={{ width: 18, height: 18 }} />
                  <label htmlFor="featured" style={{ margin: 0, cursor: 'pointer' }}>
                    ⭐ Mark as Featured Project
                  </label>
                </div>
              </div>
              <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', marginTop: 8 }}>
                <button type="button" className="btn" style={{ background: '#f1f5f9' }}
                  onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" style={{ width: 'auto' }}>
                  {editing ? 'Update' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}