import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AdminLayout from '../../components/AdminLayout';
import API from '../../api/axios';

export default function AdminDashboard() {
  const [stats, setStats] = useState({
    projects: 0, services: 0, skills: 0,
    testimonials: 0, blogs: 0, messages: 0,
  });
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    // Fetch counts from all modules
    Promise.all([
      API.get('/api/projects?perPage=1'),
      API.get('/api/services'),
      API.get('/api/skills'),
      API.get('/api/testimonials?perPage=1'),
      API.get('/api/blog/admin/all?perPage=1'),
      API.get('/api/contact?perPage=5'),
    ]).then(([p, s, sk, t, b, c]) => {
      setStats({
        projects:     p.data.pagination?.total || p.data.data?.length || 0,
        services:     s.data.data?.length || 0,
        skills:       sk.data.data?.length || 0,
        testimonials: t.data.pagination?.total || t.data.data?.length || 0,
        blogs:        b.data.pagination?.total || b.data.data?.length || 0,
        messages:     c.data.pagination?.total || c.data.data?.length || 0,
      });
      setMessages(c.data.data || []);
    }).catch(() => {});
  }, []);

  const statCards = [
    { label: 'Projects',     value: stats.projects,     icon: '📁', link: '/admin/projects',     color: '#3b82f6' },
    { label: 'Services',     value: stats.services,     icon: '⚡', link: '/admin/services',     color: '#8b5cf6' },
    { label: 'Skills',       value: stats.skills,       icon: '💡', link: '/admin/skills',       color: '#f59e0b' },
    { label: 'Testimonials', value: stats.testimonials, icon: '⭐', link: '/admin/testimonials', color: '#10b981' },
    { label: 'Blog Posts',   value: stats.blogs,        icon: '✍️', link: '/admin/blog',         color: '#ef4444' },
    { label: 'Messages',     value: stats.messages,     icon: '📩', link: '/admin/contact',      color: '#06b6d4' },
  ];

  return (
    <AdminLayout>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: 32,
      }}>
        <div>
          <h1 style={{ fontSize: 28, fontWeight: 700 }}>Dashboard</h1>
          <p style={{ color: 'var(--gray)', marginTop: 4 }}>
            Welcome back! Here's your portfolio overview.
          </p>
        </div>
        <div style={{ fontSize: 13, color: 'var(--gray)' }}>
          {new Date().toLocaleDateString('en-US', {
            weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
          })}
        </div>
      </div>

      {/* Stats Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))',
        gap: 20,
        marginBottom: 32,
      }}>
        {statCards.map((card, i) => (
          <Link
            to={card.link}
            key={i}
            style={{
              background: 'white',
              borderRadius: 16,
              padding: '24px 20px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.06)',
              border: '1px solid var(--border)',
              textDecoration: 'none',
              display: 'block',
              transition: 'all 0.2s',
            }}
            onMouseEnter={e => {
              e.currentTarget.style.transform = 'translateY(-4px)';
              e.currentTarget.style.boxShadow = '0 8px 24px rgba(0,0,0,0.1)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 2px 8px rgba(0,0,0,0.06)';
            }}
          >
            <div style={{
              width: 48,
              height: 48,
              borderRadius: 12,
              background: `${card.color}15`,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 22,
              marginBottom: 16,
            }}>
              {card.icon}
            </div>
            <div style={{
              fontSize: 32,
              fontWeight: 800,
              color: card.color,
              fontFamily: 'Poppins, sans-serif',
              lineHeight: 1,
              marginBottom: 6,
            }}>
              {card.value}
            </div>
            <div style={{ fontSize: 13, color: 'var(--gray)' }}>
              {card.label}
            </div>
          </Link>
        ))}
      </div>

      {/* Recent Messages */}
      <div style={{
        background: 'white',
        borderRadius: 16,
        padding: 24,
        boxShadow: '0 2px 8px rgba(0,0,0,0.06)',
        border: '1px solid var(--border)',
      }}>
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 20,
        }}>
          <h2 style={{ fontSize: 18, fontWeight: 600 }}>📩 Recent Messages</h2>
          <Link
            to="/admin/contact"
            style={{ fontSize: 13, color: 'var(--primary)', fontWeight: 600 }}
          >
            View All →
          </Link>
        </div>

        {messages.length === 0 ? (
          <p style={{ color: 'var(--gray)', textAlign: 'center', padding: 20 }}>
            No messages yet
          </p>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
            <thead>
              <tr>
                {['Name', 'Email', 'Subject', 'Status', 'Date'].map(h => (
                  <th key={h} style={{
                    padding: '10px 12px',
                    textAlign: 'left',
                    background: '#f8fafc',
                    color: 'var(--gray)',
                    fontSize: 12,
                    fontWeight: 600,
                    borderBottom: '1px solid var(--border)',
                  }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {messages.map((msg, i) => (
                <tr key={msg.id || i}>
                  <td style={{ padding: '12px', borderBottom: '1px solid #f0f0f0', fontWeight: 500 }}>
                    {msg.name}
                  </td>
                  <td style={{ padding: '12px', borderBottom: '1px solid #f0f0f0', color: 'var(--gray)' }}>
                    {msg.email}
                  </td>
                  <td style={{ padding: '12px', borderBottom: '1px solid #f0f0f0' }}>
                    {msg.subject || '—'}
                  </td>
                  <td style={{ padding: '12px', borderBottom: '1px solid #f0f0f0' }}>
                    <span style={{
                      padding: '3px 10px',
                      borderRadius: 20,
                      fontSize: 11,
                      fontWeight: 600,
                      background: msg.status === 'unread' ? 'rgba(239,68,68,0.1)' : 'rgba(34,197,94,0.1)',
                      color: msg.status === 'unread' ? '#ef4444' : '#22c55e',
                    }}>
                      {msg.status}
                    </span>
                  </td>
                  <td style={{ padding: '12px', borderBottom: '1px solid #f0f0f0', color: 'var(--gray)', fontSize: 12 }}>
                    {new Date(msg.created_at).toLocaleDateString()}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </AdminLayout>
  );
}