import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import AdminLayout from '../../components/AdminLayout';
import API from '../../api/axios';

export default function AdminBlog() {
  const [blogs, setBlogs]         = useState([]);
  const [loading, setLoading]     = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing]     = useState(null);
  const [image, setImage]         = useState(null);
  const [form, setForm] = useState({
    title: '', content: '', excerpt: '',
    category: '', tags: '', status: 'draft',
  });

  useEffect(() => { fetchBlogs(); }, []);

  const fetchBlogs = () => {
    setLoading(true);
    API.get('/api/blog/admin/all?perPage=50')
      .then(({ data }) => { setBlogs(data.data || []); setLoading(false); })
      .catch(() => setLoading(false));
  };

  const openCreate = () => {
    setEditing(null);
    setImage(null);
    setForm({ title: '', content: '', excerpt: '', category: '', tags: '', status: 'draft' });
    setShowModal(true);
  };

  const openEdit = (blog) => {
    setEditing(blog);
    setImage(null);
    setForm({
      title:    blog.title,
      content:  blog.content,
      excerpt:  blog.excerpt  || '',
      category: blog.category || '',
      tags:     blog.tags     || '',
      status:   blog.status   || 'draft',
    });
    setShowModal(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      Object.keys(form).forEach(key => formData.append(key, form[key]));
      if (image) formData.append('image', image);

      if (editing) {
        await API.put(`/api/blog/${editing.id}`, formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Blog post updated!');
      } else {
        await API.post('/api/blog', formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Blog post created!');
      }
      setShowModal(false);
      fetchBlogs();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Something went wrong');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this blog post?')) return;
    try {
      await API.delete(`/api/blog/${id}`);
      toast.success('Blog post deleted!');
      fetchBlogs();
    } catch {
      toast.error('Failed to delete');
    }
  };

  return (
    <AdminLayout>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 700 }}>✍️ Blog Posts</h1>
          <p style={{ color: 'var(--gray)', marginTop: 4 }}>Manage your blog articles</p>
        </div>
        <button className="btn btn-primary" onClick={openCreate}>+ New Post</button>
      </div>

      <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid var(--border)', overflow: 'hidden' }}>
        {loading ? (
          <div className="loading"><div className="loading-spinner"></div></div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
            <thead>
              <tr>
                {['Image', 'Title', 'Category', 'Status', 'Views', 'Date', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '14px 16px', textAlign: 'left', background: '#f8fafc', color: 'var(--gray)', fontSize: 12, fontWeight: 600, borderBottom: '1px solid var(--border)' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {blogs.length === 0 ? (
                <tr><td colSpan="7" style={{ textAlign: 'center', padding: 40, color: 'var(--gray)' }}>No blog posts yet</td></tr>
              ) : blogs.map(blog => (
                <tr key={blog.id} style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ width: 60, height: 45, borderRadius: 8, overflow: 'hidden', background: '#f0f7ff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24 }}>
                      {blog.image
                        ? <img src={`http://localhost:4000/${blog.image}`} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                        : '✍️'}
                    </div>
                  </td>
                  <td style={{ padding: '12px 16px', fontWeight: 500, maxWidth: 200 }}>
                    <div style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {blog.title}
                    </div>
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    {blog.category && (
                      <span style={{ padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600, background: 'rgba(37,99,235,0.1)', color: 'var(--primary)' }}>
                        {blog.category}
                      </span>
                    )}
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <span style={{ padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600, background: blog.status === 'published' ? 'rgba(34,197,94,0.1)' : 'rgba(245,158,11,0.1)', color: blog.status === 'published' ? '#22c55e' : '#f59e0b' }}>
                      {blog.status}
                    </span>
                  </td>
                  <td style={{ padding: '12px 16px', color: 'var(--gray)' }}>👁 {blog.views}</td>
                  <td style={{ padding: '12px 16px', color: 'var(--gray)', fontSize: 12 }}>
                    {new Date(blog.created_at).toLocaleDateString()}
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button className="btn btn-warning btn-sm" onClick={() => openEdit(blog)}>Edit</button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleDelete(blog.id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 20 }}
          onClick={() => setShowModal(false)}>
          <div style={{ background: 'white', borderRadius: 16, padding: 32, width: '100%', maxWidth: 680, maxHeight: '90vh', overflowY: 'auto' }}
            onClick={e => e.stopPropagation()}>
            <h3 style={{ marginBottom: 24, fontSize: 18, fontWeight: 600 }}>
              {editing ? '✏️ Edit Blog Post' : '➕ New Blog Post'}
            </h3>
            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Title *</label>
                  <input type="text" placeholder="Blog post title..." value={form.title}
                    onChange={e => setForm({ ...form, title: e.target.value })} required />
                </div>
                <div className="form-group">
                  <label>Category</label>
                  <input type="text" placeholder="Laravel, Node.js, Career..." value={form.category}
                    onChange={e => setForm({ ...form, category: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>Tags (comma separated)</label>
                  <input type="text" placeholder="php, api, backend" value={form.tags}
                    onChange={e => setForm({ ...form, tags: e.target.value })} />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Excerpt (short summary)</label>
                  <textarea
                    placeholder="Brief summary of the post..."
                    value={form.excerpt}
                    onChange={e => setForm({ ...form, excerpt: e.target.value })}
                    style={{ minHeight: 70 }}
                  />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Content * (HTML supported)</label>
                  <textarea
                    placeholder="Write your blog post content here... HTML tags are supported."
                    value={form.content}
                    onChange={e => setForm({ ...form, content: e.target.value })}
                    required
                    style={{ minHeight: 200, fontFamily: 'monospace', fontSize: 13 }}
                  />
                </div>
                <div className="form-group">
                  <label>Status</label>
                  <select value={form.status}
                    onChange={e => setForm({ ...form, status: e.target.value })}>
                    <option value="draft">📝 Draft</option>
                    <option value="published">✅ Published</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>Featured Image</label>
                  <input type="file" accept="image/*"
                    onChange={e => setImage(e.target.files[0])} />
                  {editing?.image && !image && (
                    <img src={`http://localhost:4000/${editing.image}`} alt=""
                      style={{ marginTop: 8, height: 60, borderRadius: 8 }} />
                  )}
                </div>
              </div>
              <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', marginTop: 8 }}>
                <button type="button" className="btn" style={{ background: '#f1f5f9' }}
                  onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" style={{ width: 'auto' }}>
                  {editing ? 'Update Post' : 'Publish Post'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}