import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import Hero from '../components/Hero';
import API from '../api/axios';

export default function Home() {
  const [services, setServices]           = useState([]);
  const [projects, setProjects]           = useState([]);
  const [testimonials, setTestimonials]   = useState([]);
  const [blogs, setBlogs]                 = useState([]);
  const [loading, setLoading]             = useState(true);

  useEffect(() => {
    AOS.init({ duration: 800, once: true, offset: 100 });

    // Fetch all data
    Promise.all([
      API.get('/api/services'),
      API.get('/api/projects/featured'),
      API.get('/api/testimonials/featured'),
      API.get('/api/blog/recent?limit=3'),
    ]).then(([s, p, t, b]) => {
      setServices(s.data.data || []);
      setProjects(p.data.data || []);
      setTestimonials(t.data.data || []);
      setBlogs(b.data.data || []);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  return (
    <>
      <Navbar />
      <Hero />

      {/* ===== SERVICES ===== */}
      <section className="section" id="services">
        <div className="container">
          <div className="section-header" data-aos="fade-up">
            <span className="section-tag">What I Do</span>
            <h2 className="section-title">My <span>Services</span></h2>
            <p className="section-subtitle">
              I offer a wide range of web development services to help
              your business grow online
            </p>
          </div>

          <div className="services-grid">
            {loading ? (
              <div className="loading"><div className="loading-spinner"></div>Loading...</div>
            ) : services.length === 0 ? (
              // Default services if none in DB
              [
                { icon: '⚡', title: 'Laravel Development', description: 'Building scalable, high-performance web applications with Laravel framework using best practices and clean architecture.', price_from: 'From $500' },
                { icon: '🚀', title: 'Node.js & NestJS APIs', description: 'RESTful APIs and microservices with Node.js and NestJS. JWT auth, file uploads, pagination and more.', price_from: 'From $400' },
                { icon: '🛒', title: 'E-Commerce Development', description: 'Custom WooCommerce, Shopify, OpenCart solutions with payment gateways and shipping integrations.', price_from: 'From $600' },
                { icon: '🔧', title: 'Bug Fixing & Optimization', description: 'I specialize in fixing complex bugs, performance optimization and taking over difficult legacy projects.', price_from: 'From $50/hr' },
                { icon: '🌐', title: 'WordPress Development', description: 'Custom WordPress themes, plugins and WooCommerce stores tailored to your business needs.', price_from: 'From $300' },
                { icon: '🔗', title: 'API Integration', description: 'Third-party API integrations including payment gateways, shipping, CRMs, and social platforms.', price_from: 'From $200' },
              ].map((service, i) => (
                <div className="service-card" key={i} data-aos="fade-up" data-aos-delay={i * 100}>
                  <div className="service-icon">{service.icon}</div>
                  <h3 className="service-title">{service.title}</h3>
                  <p className="service-desc">{service.description}</p>
                  <div className="service-price">{service.price_from}</div>
                </div>
              ))
            ) : services.map((service, i) => (
              <div className="service-card" key={service.id} data-aos="fade-up" data-aos-delay={i * 100}>
                <div className="service-icon">{service.icon || '⚡'}</div>
                <h3 className="service-title">{service.title}</h3>
                <p className="service-desc">{service.description}</p>
                {service.price_from && (
                  <div className="service-price">{service.price_from}</div>
                )}
              </div>
            ))}
          </div>

          <div style={{ textAlign: 'center', marginTop: 40 }} data-aos="fade-up">
            <Link to="/services" className="btn btn-outline">
              View All Services →
            </Link>
          </div>
        </div>
      </section>

      {/* ===== FEATURED PROJECTS ===== */}
      <section className="section" style={{ background: 'var(--light)' }}>
        <div className="container">
          <div className="section-header" data-aos="fade-up">
            <span className="section-tag">My Work</span>
            <h2 className="section-title">Featured <span>Projects</span></h2>
            <p className="section-subtitle">
              A selection of my best work across different industries and technologies
            </p>
          </div>

          <div className="portfolio-grid">
            {projects.length === 0 ? (
              [
                { title: 'E-Commerce Platform', category: 'web', description: 'Full-featured WooCommerce store with custom payment gateway integration and inventory management.', tech_stack: 'Laravel,React,MySQL,Stripe' },
                { title: 'SaaS Dashboard', category: 'web', description: 'Multi-tenant SaaS application with role-based access control and real-time analytics.', tech_stack: 'NestJS,React,TypeORM,JWT' },
                { title: 'REST API System', category: 'api', description: 'High-performance REST API serving 50K+ requests/day with caching and rate limiting.', tech_stack: 'Node.js,Express,Redis,MySQL' },
              ].map((project, i) => (
                <div className="project-card" key={i} data-aos="fade-up" data-aos-delay={i * 100}>
                  <div className="project-image">
                    <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 60, background: `hsl(${i * 60 + 200}, 70%, 95%)` }}>
                      {['🛒', '📊', '🔗'][i]}
                    </div>
                    <div className="project-overlay">
                      <span className="project-link">🔗</span>
                      <span className="project-link">📂</span>
                    </div>
                  </div>
                  <div className="project-body">
                    <div className="project-category">{project.category}</div>
                    <h3 className="project-title">{project.title}</h3>
                    <p className="project-desc">{project.description}</p>
                    <div className="project-tags">
                      {project.tech_stack.split(',').map(tag => (
                        <span key={tag} className="project-tag">{tag}</span>
                      ))}
                    </div>
                  </div>
                </div>
              ))
            ) : projects.map((project, i) => (
              <div className="project-card" key={project.id} data-aos="fade-up" data-aos-delay={i * 100}>
                <div className="project-image">
                  {project.image ? (
                    <img src={`http://localhost:4000/${project.image}`} alt={project.title} />
                  ) : (
                    <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 60 }}>
                      📁
                    </div>
                  )}
                  <div className="project-overlay">
                    {project.live_url && <a href={project.live_url} target="_blank" rel="noreferrer" className="project-link">🔗</a>}
                    {project.github_url && <a href={project.github_url} target="_blank" rel="noreferrer" className="project-link">📂</a>}
                  </div>
                </div>
                <div className="project-body">
                  <div className="project-category">{project.category}</div>
                  <h3 className="project-title">{project.title}</h3>
                  <p className="project-desc">{project.description}</p>
                  {project.tech_stack && (
                    <div className="project-tags">
                      {project.tech_stack.split(',').map(tag => (
                        <span key={tag} className="project-tag">{tag.trim()}</span>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>

          <div style={{ textAlign: 'center', marginTop: 40 }} data-aos="fade-up">
            <Link to="/portfolio" className="btn btn-primary">
              View All Projects 🚀
            </Link>
          </div>
        </div>
      </section>

      {/* ===== TESTIMONIALS ===== */}
      <section className="section">
        <div className="container">
          <div className="section-header" data-aos="fade-up">
            <span className="section-tag">Client Reviews</span>
            <h2 className="section-title">What Clients <span>Say</span></h2>
            <p className="section-subtitle">
              Don't just take my word for it — hear from my satisfied clients
            </p>
          </div>

          <div className="testimonials-grid">
            {testimonials.length === 0 ? (
              [
                { client_name: 'John Smith', client_title: 'CEO, TechStartup', client_country: '🇺🇸', message: 'Exceptional work! Delivered our Laravel API ahead of schedule with perfect code quality. Highly recommended for any complex PHP project.', rating: 5 },
                { client_name: 'Sarah Johnson', client_title: 'Product Manager', client_country: '🇬🇧', message: 'Fixed a critical bug in our legacy system that 3 other developers failed to solve. Outstanding problem-solving skills!', rating: 5 },
                { client_name: 'Ahmed Al-Rashid', client_title: 'E-commerce Owner', client_country: '🇦🇪', message: 'Built our WooCommerce store from scratch. Professional, communicative and delivered exactly what we needed.', rating: 5 },
              ].map((t, i) => (
                <div className="testimonial-card" key={i} data-aos="fade-up" data-aos-delay={i * 100}>
                  <div className="testimonial-quote">"</div>
                  <div className="testimonial-stars">
                    {[...Array(t.rating)].map((_, j) => (
                      <span key={j} className="star">★</span>
                    ))}
                  </div>
                  <p className="testimonial-text">{t.message}</p>
                  <div className="testimonial-author">
                    <div className="testimonial-avatar">{t.client_country}</div>
                    <div>
                      <div className="testimonial-name">{t.client_name}</div>
                      <div className="testimonial-title">{t.client_title}</div>
                    </div>
                  </div>
                </div>
              ))
            ) : testimonials.map((t, i) => (
              <div className="testimonial-card" key={t.id} data-aos="fade-up" data-aos-delay={i * 100}>
                <div className="testimonial-quote">"</div>
                <div className="testimonial-stars">
                  {[...Array(t.rating || 5)].map((_, j) => (
                    <span key={j} className="star">★</span>
                  ))}
                </div>
                <p className="testimonial-text">{t.message}</p>
                <div className="testimonial-author">
                  {t.client_avatar ? (
                    <img className="testimonial-avatar" src={`http://localhost:4000/${t.client_avatar}`} alt={t.client_name} />
                  ) : (
                    <div className="testimonial-avatar">👤</div>
                  )}
                  <div>
                    <div className="testimonial-name">{t.client_name}</div>
                    <div className="testimonial-title">{t.client_title} {t.client_country && `· ${t.client_country}`}</div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ===== RECENT BLOGS ===== */}
      <section className="section" style={{ background: 'var(--light)' }}>
        <div className="container">
          <div className="section-header" data-aos="fade-up">
            <span className="section-tag">Latest Articles</span>
            <h2 className="section-title">From The <span>Blog</span></h2>
            <p className="section-subtitle">
              Tips, tutorials and insights on web development
            </p>
          </div>

          <div className="blog-grid">
            {blogs.length === 0 ? (
              [
                { title: 'Building REST APIs with NestJS and TypeORM', category: 'Node.js', excerpt: 'A complete guide to building production-ready REST APIs using NestJS framework with TypeORM and MySQL database.', created_at: new Date(), views: 245 },
                { title: 'Laravel Best Practices in 2026', category: 'Laravel', excerpt: 'Essential best practices every Laravel developer should follow for clean, maintainable and scalable code.', created_at: new Date(), views: 312 },
                { title: 'How to Become a Top-Rated Freelancer on Upwork', category: 'Career', excerpt: 'Proven strategies to build your Upwork profile, win clients and grow your freelance income consistently.', created_at: new Date(), views: 189 },
              ].map((blog, i) => (
                <div className="blog-card" key={i} data-aos="fade-up" data-aos-delay={i * 100}>
                  <div className="blog-image">
                    <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 60, background: `hsl(${i * 60 + 200}, 70%, 95%)` }}>
                      {['💻', '🔧', '💼'][i]}
                    </div>
                  </div>
                  <div className="blog-body">
                    <div className="blog-meta">
                      <span className="blog-category">{blog.category}</span>
                      <span className="blog-date">
                        {new Date(blog.created_at).toLocaleDateString()}
                      </span>
                    </div>
                    <h3 className="blog-title">{blog.title}</h3>
                    <p className="blog-excerpt">{blog.excerpt}</p>
                    <div className="blog-footer">
                      <span className="blog-read-more">Read More →</span>
                      <span className="blog-views">👁 {blog.views}</span>
                    </div>
                  </div>
                </div>
              ))
            ) : blogs.map((blog, i) => (
              <Link to={`/blog/${blog.slug}`} className="blog-card" key={blog.id} data-aos="fade-up" data-aos-delay={i * 100}>
                <div className="blog-image">
                  {blog.image ? (
                    <img src={`http://localhost:4000/${blog.image}`} alt={blog.title} />
                  ) : (
                    <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 60, background: `hsl(${i * 60 + 200}, 70%, 95%)` }}>
                      ✍️
                    </div>
                  )}
                </div>
                <div className="blog-body">
                  <div className="blog-meta">
                    <span className="blog-category">{blog.category}</span>
                    <span className="blog-date">
                      {new Date(blog.created_at).toLocaleDateString()}
                    </span>
                  </div>
                  <h3 className="blog-title">{blog.title}</h3>
                  <p className="blog-excerpt">{blog.excerpt}</p>
                  <div className="blog-footer">
                    <span className="blog-read-more">Read More →</span>
                    <span className="blog-views">👁 {blog.views}</span>
                  </div>
                </div>
              </Link>
            ))}
          </div>

          <div style={{ textAlign: 'center', marginTop: 40 }} data-aos="fade-up">
            <Link to="/blog" className="btn btn-outline">
              View All Articles →
            </Link>
          </div>
        </div>
      </section>

     {/* ===== CTA SECTION ===== */}
     <div style={{ display: 'flex', gap: 16, justifyContent: 'center', flexWrap: 'wrap' }}>
            <Link to="/contact" className="btn btn-white">
              Get In Touch 📩
            </Link>
            
             <a href="https://upwork.com"
              target="_blank"
              rel="noreferrer"
              className="btn btn-outline"
              style={{ borderColor: 'white', color: 'white' }}
            >
              Hire on Upwork 🟢
            </a>
          </div>

      <Footer />
    </>
  );
}