import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import AdminLayout from '../../components/AdminLayout';
import API from '../../api/axios';

export default function AdminServices() {
  const [services, setServices]   = useState([]);
  const [loading, setLoading]     = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing]     = useState(null);
  const [form, setForm] = useState({
    title: '', description: '', icon: '⚡',
    price_from: '', sort_order: 0, is_active: true,
  });

  useEffect(() => { fetchServices(); }, []);

  const fetchServices = () => {
    setLoading(true);
    API.get('/api/services/admin/all')
      .then(({ data }) => { setServices(data.data || []); setLoading(false); })
      .catch(() => {
        API.get('/api/services')
          .then(({ data }) => { setServices(data.data || []); setLoading(false); })
          .catch(() => setLoading(false));
      });
  };

  const openCreate = () => {
    setEditing(null);
    setForm({ title: '', description: '', icon: '⚡', price_from: '', sort_order: 0, is_active: true });
    setShowModal(true);
  };

  const openEdit = (service) => {
    setEditing(service);
    setForm({
      title:       service.title,
      description: service.description,
      icon:        service.icon        || '⚡',
      price_from:  service.price_from  || '',
      sort_order:  service.sort_order  || 0,
      is_active:   service.is_active   ?? true,
    });
    setShowModal(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editing) {
        await API.put(`/api/services/${editing.id}`, form);
        toast.success('Service updated!');
      } else {
        await API.post('/api/services', form);
        toast.success('Service created!');
      }
      setShowModal(false);
      fetchServices();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Something went wrong');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this service?')) return;
    try {
      await API.delete(`/api/services/${id}`);
      toast.success('Service deleted!');
      fetchServices();
    } catch {
      toast.error('Failed to delete');
    }
  };

  return (
    <AdminLayout>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 700 }}>⚡ Services</h1>
          <p style={{ color: 'var(--gray)', marginTop: 4 }}>Manage your service offerings</p>
        </div>
        <button className="btn btn-primary" onClick={openCreate}>+ Add Service</button>
      </div>

      <div style={{ background: 'white', borderRadius: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)', border: '1px solid var(--border)', overflow: 'hidden' }}>
        {loading ? (
          <div className="loading"><div className="loading-spinner"></div></div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
            <thead>
              <tr>
                {['Icon', 'Title', 'Price From', 'Status', 'Order', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '14px 16px', textAlign: 'left', background: '#f8fafc', color: 'var(--gray)', fontSize: 12, fontWeight: 600, borderBottom: '1px solid var(--border)' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {services.length === 0 ? (
                <tr><td colSpan="6" style={{ textAlign: 'center', padding: 40, color: 'var(--gray)' }}>No services yet</td></tr>
              ) : services.map(service => (
                <tr key={service.id} style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '12px 16px', fontSize: 24 }}>{service.icon}</td>
                  <td style={{ padding: '12px 16px', fontWeight: 500 }}>{service.title}</td>
                  <td style={{ padding: '12px 16px', color: 'var(--primary)', fontWeight: 600 }}>{service.price_from || '—'}</td>
                  <td style={{ padding: '12px 16px' }}>
                    <span style={{ padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 600, background: service.is_active ? 'rgba(34,197,94,0.1)' : 'rgba(239,68,68,0.1)', color: service.is_active ? '#22c55e' : '#ef4444' }}>
                      {service.is_active ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td style={{ padding: '12px 16px', color: 'var(--gray)' }}>{service.sort_order}</td>
                  <td style={{ padding: '12px 16px' }}>
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button className="btn btn-warning btn-sm" onClick={() => openEdit(service)}>Edit</button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleDelete(service.id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 20 }}
          onClick={() => setShowModal(false)}>
          <div style={{ background: 'white', borderRadius: 16, padding: 32, width: '100%', maxWidth: 520, maxHeight: '90vh', overflowY: 'auto' }}
            onClick={e => e.stopPropagation()}>
            <h3 style={{ marginBottom: 24, fontSize: 18, fontWeight: 600 }}>
              {editing ? '✏️ Edit Service' : '➕ Add Service'}
            </h3>
            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Title *</label>
                  <input type="text" placeholder="Laravel Development" value={form.title}
                    onChange={e => setForm({ ...form, title: e.target.value })} required />
                </div>
                <div className="form-group" style={{ gridColumn: '1/-1' }}>
                  <label>Description *</label>
                  <textarea placeholder="Describe your service..." value={form.description}
                    onChange={e => setForm({ ...form, description: e.target.value })} required />
                </div>
                <div className="form-group">
                  <label>Icon (Emoji)</label>
                  <input type="text" placeholder="⚡" value={form.icon}
                    onChange={e => setForm({ ...form, icon: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>Price From</label>
                  <input type="text" placeholder="From $500" value={form.price_from}
                    onChange={e => setForm({ ...form, price_from: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>Sort Order</label>
                  <input type="number" value={form.sort_order}
                    onChange={e => setForm({ ...form, sort_order: +e.target.value })} />
                </div>
                <div className="form-group" style={{ display: 'flex', alignItems: 'center', gap: 10, paddingTop: 24 }}>
                  <input type="checkbox" id="active" checked={form.is_active}
                    onChange={e => setForm({ ...form, is_active: e.target.checked })}
                    style={{ width: 18, height: 18 }} />
                  <label htmlFor="active" style={{ margin: 0, cursor: 'pointer' }}>Active</label>
                </div>
              </div>
              <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', marginTop: 8 }}>
                <button type="button" className="btn" style={{ background: '#f1f5f9' }} onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" style={{ width: 'auto' }}>
                  {editing ? 'Update' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}