import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AOS from 'aos';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import API from '../api/axios';

const defaultSkills = {
  backend:  [
    { name: 'Laravel / PHP', percentage: 98 },
    { name: 'Node.js', percentage: 88 },
    { name: 'NestJS', percentage: 82 },
    { name: 'Yii / Zend / CodeIgniter', percentage: 85 },
    { name: 'REST API Design', percentage: 95 },
  ],
  frontend: [
    { name: 'React.js', percentage: 80 },
    { name: 'JavaScript / jQuery', percentage: 90 },
    { name: 'HTML5 / CSS3', percentage: 92 },
    { name: 'Vue.js', percentage: 70 },
    { name: 'Bootstrap / Tailwind', percentage: 88 },
  ],
  database: [
    { name: 'MySQL', percentage: 95 },
    { name: 'TypeORM / Eloquent', percentage: 90 },
    { name: 'MongoDB', percentage: 72 },
    { name: 'Redis', percentage: 75 },
    { name: 'Database Optimization', percentage: 88 },
  ],
  tools: [
    { name: 'Git / GitHub / SVN', percentage: 95 },
    { name: 'Linux / VPS / cPanel', percentage: 85 },
    { name: 'Docker / Nginx', percentage: 75 },
    { name: 'Jira / Asana', percentage: 88 },
    { name: 'Postman / Thunder Client', percentage: 92 },
  ],
};

const categoryIcons = {
  backend:  '⚙️',
  frontend: '🎨',
  database: '🗄️',
  tools:    '🔧',
};

const categoryLabels = {
  backend:  'Backend Development',
  frontend: 'Frontend Development',
  database: 'Databases',
  tools:    'Tools & DevOps',
};

export default function Skills() {
  const [skills, setSkills]     = useState(defaultSkills);
  const [animate, setAnimate]   = useState(false);

  useEffect(() => {
    AOS.init({ duration: 800, once: true });
    API.get('/api/skills')
      .then(({ data }) => {
        if (data.grouped && Object.keys(data.grouped).length > 0) {
          setSkills(data.grouped);
        }
      })
      .catch(() => {});

    // Trigger skill bar animation after mount
    setTimeout(() => setAnimate(true), 300);
  }, []);

  return (
    <>
      <Navbar />

      <div className="page-hero">
        <div className="container">
          <h1>My <span style={{ color: 'var(--primary)' }}>Skills</span></h1>
          <p>Technologies and tools I use to build amazing products</p>
          <div className="breadcrumb">
            <Link to="/">Home</Link>
            <span>→</span>
            <span>Skills</span>
          </div>
        </div>
      </div>

      {/* Skills Grid */}
      <section className="section skills-section">
        <div className="container">
          <div className="section-header" data-aos="fade-up">
            <span className="section-tag">Expertise</span>
            <h2 className="section-title">Technical <span>Skills</span></h2>
            <p className="section-subtitle">
              12+ years of hands-on experience with these technologies
            </p>
          </div>

          <div className="skills-grid">
            {Object.keys(skills).map((category, ci) => (
              <div
                key={category}
                className="skill-category-card"
                data-aos="fade-up"
                data-aos-delay={ci * 100}
              >
                <div className="skill-category-title">
                  <span>{categoryIcons[category] || '💡'}</span>
                  {categoryLabels[category] || category}
                </div>

                {(skills[category] || []).map((skill, i) => (
                  <div className="skill-item" key={skill.name || i}>
                    <div className="skill-header">
                      <span className="skill-name">{skill.name}</span>
                      <span className="skill-percent">{skill.percentage}%</span>
                    </div>
                    <div className="skill-bar">
                      <div
                        className="skill-fill"
                        style={{ width: animate ? `${skill.percentage}%` : '0%' }}
                      />
                    </div>
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Technologies I Work With */}
      <section className="section">
        <div className="container">
          <div className="section-header" data-aos="fade-up">
            <span className="section-tag">Stack</span>
            <h2 className="section-title">Technologies I <span>Use</span></h2>
          </div>

          <div style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: 16,
            justifyContent: 'center',
          }} data-aos="fade-up">
            {[
              'Laravel', 'PHP', 'Node.js', 'NestJS', 'React.js',
              'Vue.js', 'MySQL', 'TypeORM', 'JWT', 'REST API',
              'WordPress', 'WooCommerce', 'Stripe', 'Git', 'Linux',
              'Nginx', 'Redis', 'Docker', 'TypeScript', 'JavaScript',
            ].map((tech, i) => (
              <div
                key={tech}
                data-aos="zoom-in"
                data-aos-delay={i * 30}
                style={{
                  padding: '10px 20px',
                  background: 'white',
                  borderRadius: 20,
                  border: '2px solid var(--border)',
                  fontSize: 14,
                  fontWeight: 600,
                  color: 'var(--dark)',
                  boxShadow: 'var(--shadow)',
                  transition: 'var(--transition)',
                  cursor: 'default',
                }}
                onMouseEnter={e => {
                  e.target.style.borderColor = 'var(--primary)';
                  e.target.style.color = 'var(--primary)';
                  e.target.style.transform = 'translateY(-3px)';
                }}
                onMouseLeave={e => {
                  e.target.style.borderColor = 'var(--border)';
                  e.target.style.color = 'var(--dark)';
                  e.target.style.transform = 'translateY(0)';
                }}
              >
                {tech}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Experience Stats */}
      <section className="section" style={{ background: 'var(--light)' }}>
        <div className="container">
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
            gap: 24,
            textAlign: 'center',
          }}>
            {[
              { num: '12+', label: 'Years Experience', icon: '⏱️' },
              { num: '100+', label: 'Projects Completed', icon: '✅' },
              { num: '50+', label: 'Happy Clients', icon: '😊' },
              { num: '20+', label: 'Technologies', icon: '💻' },
              { num: '99%', label: 'Client Satisfaction', icon: '⭐' },
            ].map((stat, i) => (
              <div
                key={i}
                className="card"
                data-aos="fade-up"
                data-aos-delay={i * 100}
                style={{ textAlign: 'center' }}
              >
                <div style={{ fontSize: 36, marginBottom: 8 }}>{stat.icon}</div>
                <div style={{
                  fontSize: 36,
                  fontWeight: 800,
                  color: 'var(--primary)',
                  fontFamily: 'Poppins, sans-serif',
                }}>
                  {stat.num}
                </div>
                <div style={{ fontSize: 13, color: 'var(--gray)', marginTop: 4 }}>
                  {stat.label}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <Footer />
    </>
  );
}