import { useEffect, useState } from 'react';
import { Link, useParams, useNavigate } from 'react-router-dom';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import API from '../api/axios';

export default function BlogSingle() {
  const { slug }      = useParams();
  const navigate      = useNavigate();
  const [blog, setBlog] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    window.scrollTo(0, 0);
    API.get(`/api/blog/${slug}`)
      .then(({ data }) => {
        setBlog(data.data);
        setLoading(false);
      })
      .catch(() => {
        navigate('/blog');
      });
  }, [slug]);

  if (loading) return (
    <>
      <Navbar />
      <div className="loading" style={{ minHeight: '60vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
        <div className="loading-spinner"></div>
        Loading article...
      </div>
      <Footer />
    </>
  );

  return (
    <>
      <Navbar />

      <div className="page-hero">
        <div className="container">
          <span style={{
            display: 'inline-block',
            background: 'rgba(37,99,235,0.2)',
            color: 'var(--primary)',
            padding: '4px 14px',
            borderRadius: 20,
            fontSize: 13,
            fontWeight: 600,
            marginBottom: 16,
          }}>
            {blog.category}
          </span>
          <h1 style={{ fontSize: 'clamp(24px, 4vw, 42px)', maxWidth: 700, margin: '0 auto' }}>
            {blog.title}
          </h1>
          <div style={{ marginTop: 16, color: '#94a3b8', fontSize: 14 }}>
            {new Date(blog.created_at).toLocaleDateString('en-US', {
              weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
            })} · 👁 {blog.views} views
          </div>
          <div className="breadcrumb">
            <Link to="/">Home</Link>
            <span>→</span>
            <Link to="/blog">Blog</Link>
            <span>→</span>
            <span>{blog.title.substring(0, 30)}...</span>
          </div>
        </div>
      </div>

      <section className="section">
        <div className="container">
          <div style={{ maxWidth: 780, margin: '0 auto' }}>

            {/* Featured Image */}
            {blog.image && (
              <img
                src={`http://localhost:4000/${blog.image}`}
                alt={blog.title}
                style={{
                  width: '100%',
                  height: 400,
                  objectFit: 'cover',
                  borderRadius: 'var(--radius-lg)',
                  marginBottom: 40,
                  boxShadow: 'var(--shadow-lg)',
                }}
              />
            )}

            {/* Tags */}
            {blog.tags && (
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 32 }}>
                {blog.tags.split(',').map(tag => (
                  <span key={tag} style={{
                    padding: '4px 12px',
                    background: 'rgba(37,99,235,0.08)',
                    color: 'var(--primary)',
                    borderRadius: 20,
                    fontSize: 12,
                    fontWeight: 600,
                  }}>
                    #{tag.trim()}
                  </span>
                ))}
              </div>
            )}

            {/* Content */}
            <div
              style={{
                fontSize: 16,
                lineHeight: 1.9,
                color: 'var(--dark)',
              }}
              dangerouslySetInnerHTML={{ __html: blog.content }}
            />

            {/* Back Button */}
            <div style={{ marginTop: 60, paddingTop: 32, borderTop: '1px solid var(--border)' }}>
              <Link to="/blog" className="btn btn-outline">
                ← Back to Blog
              </Link>
            </div>
          </div>
        </div>
      </section>

      <Footer />
    </>
  );
}