import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AOS from 'aos';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import API from '../api/axios';

const defaultTestimonials = [
  { client_name: 'John Smith', client_title: 'CEO, TechStartup', client_country: '🇺🇸', message: 'Exceptional work! Delivered our Laravel API ahead of schedule with perfect code quality. Highly recommended for any complex PHP project.', rating: 5 },
  { client_name: 'Sarah Johnson', client_title: 'Product Manager', client_country: '🇬🇧', message: 'Fixed a critical bug in our legacy system that 3 other developers failed to solve. Outstanding problem-solving skills!', rating: 5 },
  { client_name: 'Ahmed Al-Rashid', client_title: 'E-commerce Owner', client_country: '🇦🇪', message: 'Built our WooCommerce store from scratch. Professional, communicative and delivered exactly what we needed.', rating: 5 },
  { client_name: 'Maria Garcia', client_title: 'Startup Founder', client_country: '🇪🇸', message: 'Built our entire SaaS platform from scratch. Clean code, great communication and delivered on time. Will hire again!', rating: 5 },
  { client_name: 'David Chen', client_title: 'CTO, FinTech Co.', client_country: '🇸🇬', message: 'Excellent Node.js developer. Built our payment API with perfect security and performance. Very knowledgeable.', rating: 5 },
  { client_name: 'Emma Wilson', client_title: 'Digital Agency Owner', client_country: '🇦🇺', message: 'We have worked together on 5+ projects. Always delivers high quality work and is a pleasure to work with.', rating: 5 },
];

export default function Testimonials() {
  const [testimonials, setTestimonials] = useState([]);
  const [loading, setLoading]           = useState(true);
  const [page, setPage]                 = useState(1);
  const [pagination, setPagination]     = useState({});

  useEffect(() => {
    AOS.init({ duration: 800, once: true });
    fetchTestimonials();
  }, [page]);

  const fetchTestimonials = () => {
    setLoading(true);
    API.get(`/api/testimonials?page=${page}&perPage=6`)
      .then(({ data }) => {
        if (data.data?.length > 0) {
          setTestimonials(data.data);
          setPagination(data.pagination);
        } else {
          setTestimonials(defaultTestimonials);
        }
        setLoading(false);
      })
      .catch(() => {
        setTestimonials(defaultTestimonials);
        setLoading(false);
      });
  };

  return (
    <>
      <Navbar />

      <div className="page-hero">
        <div className="container">
          <h1>Client <span style={{ color: 'var(--primary)' }}>Reviews</span></h1>
          <p>What my clients say about working with me</p>
          <div className="breadcrumb">
            <Link to="/">Home</Link>
            <span>→</span>
            <span>Testimonials</span>
          </div>
        </div>
      </div>

      {/* Stats Bar */}
      <section style={{
        background: 'var(--primary)',
        padding: '40px 0',
        color: 'white',
      }}>
        <div className="container">
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
            gap: 24,
            textAlign: 'center',
          }}>
            {[
              { num: '50+', label: 'Happy Clients' },
              { num: '100%', label: 'Satisfaction Rate' },
              { num: '5.0', label: 'Average Rating' },
              { num: '12+', label: 'Years Experience' },
            ].map((stat, i) => (
              <div key={i}>
                <div style={{ fontSize: 36, fontWeight: 800, fontFamily: 'Poppins, sans-serif' }}>
                  {stat.num}
                </div>
                <div style={{ fontSize: 13, opacity: 0.8, marginTop: 4 }}>
                  {stat.label}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Testimonials Grid */}
      <section className="section">
        <div className="container">
          {loading ? (
            <div className="loading">
              <div className="loading-spinner"></div>
              Loading reviews...
            </div>
          ) : (
            <div className="testimonials-grid">
              {testimonials.map((t, i) => (
                <div
                  className="testimonial-card"
                  key={t.id || i}
                  data-aos="fade-up"
                  data-aos-delay={i * 80}
                >
                  <div className="testimonial-quote">"</div>
                  <div className="testimonial-stars">
                    {[...Array(t.rating || 5)].map((_, j) => (
                      <span key={j} className="star">★</span>
                    ))}
                  </div>
                  <p className="testimonial-text">{t.message}</p>
                  <div className="testimonial-author">
                    {t.client_avatar ? (
                      <img
                        className="testimonial-avatar"
                        src={`http://localhost:4000/${t.client_avatar}`}
                        alt={t.client_name}
                        style={{ width: 48, height: 48, borderRadius: '50%', objectFit: 'cover' }}
                      />
                    ) : (
                      <div className="testimonial-avatar" style={{ fontSize: 22 }}>
                        {t.client_country || '👤'}
                      </div>
                    )}
                    <div>
                      <div className="testimonial-name">{t.client_name}</div>
                      <div className="testimonial-title">
                        {t.client_title}
                        {t.client_country && ` · ${t.client_country}`}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Pagination */}
          {pagination.totalPages > 1 && (
            <div style={{
              display: 'flex',
              justifyContent: 'center',
              gap: 8,
              marginTop: 40,
            }}>
              <button
                disabled={!pagination.hasPrev}
                onClick={() => setPage(p => p - 1)}
                style={{
                  padding: '10px 20px',
                  borderRadius: 8,
                  border: '2px solid var(--border)',
                  background: 'white',
                  cursor: 'pointer',
                  fontWeight: 600,
                  opacity: !pagination.hasPrev ? 0.4 : 1,
                }}
              >
                ← Prev
              </button>
              <button
                disabled={!pagination.hasNext}
                onClick={() => setPage(p => p + 1)}
                style={{
                  padding: '10px 20px',
                  borderRadius: 8,
                  border: '2px solid var(--border)',
                  background: 'white',
                  cursor: 'pointer',
                  fontWeight: 600,
                  opacity: !pagination.hasNext ? 0.4 : 1,
                }}
              >
                Next →
              </button>
            </div>
          )}
        </div>
      </section>

      {/* Upwork CTA */}
      <section className="section" style={{ background: 'var(--light)' }}>
        <div className="container" style={{ textAlign: 'center' }} data-aos="fade-up">
          <h2 style={{ fontSize: 32, marginBottom: 16 }}>
            See My Reviews on <span style={{ color: '#14a800' }}>Upwork</span>
          </h2>
          <p style={{ color: 'var(--gray)', marginBottom: 32, fontSize: 16 }}>
            Check my verified client reviews on Upwork — the world's largest freelancing platform
          </p>
           <a
            href="https://upwork.com"
            target="_blank"
            rel="noreferrer"
            className="btn btn-primary"
          >
            View Upwork Profile 🟢
          </a>
        </div>
      </section>

      <Footer />
    </>
  );
}